INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 1, $az104r$SINGLE$az104r$::"QType", $az104r$You need to create a new cloud-only user in Microsoft Entra ID who can sign in to the Azure portal with the UPN ada@contoso.onmicrosoft.com. Which portal blade should you use?$az104r$, $az104r$[{"id":"a","text":"Microsoft Entra ID > Users > New user > Create new user"},{"id":"b","text":"Subscriptions > Access control (IAM) > Add role assignment"},{"id":"c","text":"Azure Active Directory B2C > Identity providers"},{"id":"d","text":"Resource groups > Add > Identity"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Cloud-only Entra ID users are created from Microsoft Entra ID > Users > New user > Create new user. Access control (IAM) only assigns RBAC to existing identities; B2C is for external consumer identities; resource groups cannot create users.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/entra/fundamentals/whatis","label":"Microsoft Learn — What is Microsoft Entra ID?"},{"url":"https://learn.microsoft.com/en-us/entra/fundamentals/how-to-create-delete-users","label":"Microsoft Learn — How to add or delete users in Microsoft Entra ID"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You need to create a new cloud-only user in Microsoft Entra ID who can sign in to the Azure portal with the UPN ada@contoso.onmicrosoft.com. Which portal blade should you use?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You want the membership of a security group to automatically include every user whose department attribute equals "Finance". Which group configuration is required?$az104r$, $az104r$[{"id":"a","text":"Assigned membership with the department filter"},{"id":"b","text":"Dynamic user membership with rule (user.department -eq \"Finance\")"},{"id":"c","text":"Mail-enabled distribution group"},{"id":"d","text":"Microsoft 365 group with a department label"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Dynamic membership uses an attribute-based rule to automatically add or remove members. Assigned groups require manual changes; mail-enabled DLs and M365 group labels do not auto-evaluate the department property for security access.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/entra/fundamentals/how-to-manage-groups","label":"Microsoft Learn — Manage groups in Microsoft Entra ID"},{"url":"https://learn.microsoft.com/en-us/entra/identity/users/groups-dynamic-membership","label":"Microsoft Learn — Dynamic membership rules for groups"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want the membership of a security group to automatically include every user whose department attribute equals "Finance". Which group configuration is required?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A partner organization needs to access a SharePoint site in your tenant without you provisioning a full account for each partner user. Which feature should you use?$az104r$, $az104r$[{"id":"a","text":"Microsoft Entra B2B guest invitations"},{"id":"b","text":"Pass-through authentication"},{"id":"c","text":"Azure AD Domain Services"},{"id":"d","text":"Service principal credentials"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$B2B collaboration lets you invite external users as guests; they sign in with their own identity and you assign access to resources in your tenant. Pass-through auth is for on-prem AD password validation; Azure AD DS provides managed domain services; service principals are for apps.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/entra/external-id/what-is-b2b","label":"Microsoft Learn — B2B collaboration overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A partner organization needs to access a SharePoint site in your tenant without you provisioning a full account for each partner user. Which feature should you use?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure RBAC role grants full management of an Azure resource, including the ability to assign roles to others?$az104r$, $az104r$[{"id":"a","text":"Contributor"},{"id":"b","text":"Reader"},{"id":"c","text":"Owner"},{"id":"d","text":"User Access Administrator"}]$az104r$::jsonb, $az104r$["c"]$az104r$::jsonb, $az104r$Owner grants full access to manage all resources, including assigning roles. Contributor can manage resources but cannot grant access. Reader is read-only. User Access Administrator can manage user access but not the resources themselves.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/role-based-access-control/overview","label":"Microsoft Learn — What is Azure RBAC?"},{"url":"https://learn.microsoft.com/en-us/azure/role-based-access-control/built-in-roles","label":"Microsoft Learn — Azure built-in roles"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure RBAC role grants full management of an Azure resource, including the ability to assign roles to others?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 3, $az104r$MULTI$az104r$::"QType", $az104r$Select ALL true statements about Azure RBAC scope inheritance.$az104r$, $az104r$[{"id":"a","text":"A role assignment at the management-group scope is inherited by all child subscriptions, resource groups, and resources."},{"id":"b","text":"Role assignments at a child scope override and remove inherited permissions from the parent."},{"id":"c","text":"A resource group-scoped role applies to every resource in that resource group."},{"id":"d","text":"Permissions from multiple inherited assignments are additive (union of allow rules)."}]$az104r$::jsonb, $az104r$["a","c","d"]$az104r$::jsonb, $az104r$RBAC is additive and inherits downward from management group > subscription > resource group > resource. Child assignments grant additional rights but do not remove inherited rights (deny assignments are a separate, restricted mechanism).$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/role-based-access-control/overview","label":"Microsoft Learn — What is Azure RBAC?"},{"url":"https://learn.microsoft.com/en-us/azure/governance/management-groups/overview","label":"Microsoft Learn — Organize your resources with management groups"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Select ALL true statements about Azure RBAC scope inheritance.$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You want to enforce that all new virtual machines in a subscription are deployed only in the eastus and westus regions. Which Azure governance feature should you use?$az104r$, $az104r$[{"id":"a","text":"A resource lock of type CanNotDelete on the subscription"},{"id":"b","text":"An Azure Policy with the \"Allowed locations\" built-in definition assigned at the subscription scope"},{"id":"c","text":"A Conditional Access policy filtered by IP"},{"id":"d","text":"A management group permission boundary"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Azure Policy with the "Allowed locations" definition uses the deny effect to block resource creation in disallowed regions. Resource locks prevent delete/modify, not placement. Conditional Access governs user sign-ins. Management groups organize subscriptions but do not enforce location.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/governance/policy/overview","label":"Microsoft Learn — What is Azure Policy?"},{"url":"https://learn.microsoft.com/en-us/azure/governance/policy/concepts/effect-basics","label":"Microsoft Learn — Understand Azure Policy effects"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want to enforce that all new virtual machines in a subscription are deployed only in the eastus and westus regions. Which Azure governance feature should you use?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which resource lock type allows reads and updates but prevents deletion?$az104r$, $az104r$[{"id":"a","text":"ReadOnly"},{"id":"b","text":"CanNotDelete"},{"id":"c","text":"NoDelete"},{"id":"d","text":"Restricted"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$CanNotDelete permits authorized users to read and modify a resource but blocks deletion. ReadOnly blocks both delete and modify. NoDelete and Restricted are not valid Azure lock levels.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-resource-manager/management/lock-resources","label":"Microsoft Learn — Lock resources to prevent unexpected changes"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which resource lock type allows reads and updates but prevents deletion?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You must apply the tag costCenter=1001 to every resource in a resource group and ensure new resources inherit it. Which approach is best?$az104r$, $az104r$[{"id":"a","text":"Manually tag each resource"},{"id":"b","text":"Use an Azure Policy with the \"Inherit a tag from the resource group if missing\" modify effect"},{"id":"c","text":"Apply a CanNotDelete lock"},{"id":"d","text":"Create a custom RBAC role that includes tag values"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Azure Policy includes built-in "Inherit a tag" definitions using the modify effect to add or update tags. RBAC roles do not set tag values, locks do not tag, and manual tagging does not scale or self-heal.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-resource-manager/management/tag-resources","label":"Microsoft Learn — Use tags to organize your Azure resources"},{"url":"https://learn.microsoft.com/en-us/azure/governance/policy/concepts/effect-basics","label":"Microsoft Learn — Understand Azure Policy effects"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You must apply the tag costCenter=1001 to every resource in a resource group and ensure new resources inherit it. Which approach is best?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A user reports being prompted for a second factor on every sign-in. Which Entra ID feature is most likely causing this and is the correct place to refine the requirement?$az104r$, $az104r$[{"id":"a","text":"Self-service password reset"},{"id":"b","text":"Conditional Access policies with MFA grant control"},{"id":"c","text":"Azure RBAC built-in roles"},{"id":"d","text":"Resource locks"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Conditional Access policies evaluate sign-in conditions and can require MFA. Refining the conditions (trusted locations, sign-in risk, device compliance) reduces unnecessary prompts. SSPR is for password recovery; RBAC and locks are unrelated to authentication.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"},{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-mfa-howitworks","label":"Microsoft Learn — Microsoft Entra multifactor authentication"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A user reports being prompted for a second factor on every sign-in. Which Entra ID feature is most likely causing this and is the correct place to refine the requirement?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You need a custom RBAC role that lets a team start and restart VMs but not delete them. Which property of the role definition lists the allowed operations?$az104r$, $az104r$[{"id":"a","text":"NotActions"},{"id":"b","text":"AssignableScopes"},{"id":"c","text":"Actions"},{"id":"d","text":"DataActions"}]$az104r$::jsonb, $az104r$["c"]$az104r$::jsonb, $az104r$The Actions array enumerates allowed control-plane operations (e.g., Microsoft.Compute/virtualMachines/start/action). NotActions subtracts from Actions, AssignableScopes lists where the role can be assigned, and DataActions covers data-plane operations.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/role-based-access-control/custom-roles","label":"Microsoft Learn — Azure custom roles"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You need a custom RBAC role that lets a team start and restart VMs but not delete them. Which property of the role definition lists the allowed operations?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$A subscription is moved under a new management group that has a Policy assignment with the deny effect for public IPs. Which statement is correct?$az104r$, $az104r$[{"id":"a","text":"Existing public IPs in the subscription are deleted automatically."},{"id":"b","text":"New deployments that violate the policy are blocked, while existing non-compliant resources are reported as non-compliant."},{"id":"c","text":"The policy has no effect until reassigned at the subscription scope."},{"id":"d","text":"Only resource groups created after the move are evaluated."}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Inherited deny policies block new non-compliant deployments; existing resources are not deleted but show as non-compliant in the Policy compliance view. Inheritance is automatic from management group through child subscriptions.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/governance/policy/overview","label":"Microsoft Learn — What is Azure Policy?"},{"url":"https://learn.microsoft.com/en-us/azure/governance/policy/concepts/effect-basics","label":"Microsoft Learn — Understand Azure Policy effects"},{"url":"https://learn.microsoft.com/en-us/azure/governance/management-groups/overview","label":"Microsoft Learn — Organize your resources with management groups"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A subscription is moved under a new management group that has a Policy assignment with the deny effect for public IPs. Which statement is correct?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$TRUE_FALSE$az104r$::"QType", $az104r$True or False: An Azure Policy initiative is a collection of policy definitions grouped together to achieve a single overall compliance goal.$az104r$, $az104r$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only for tagging policies"},{"id":"d","text":"Only for management groups"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$True. An initiative (policy set) groups multiple policy definitions so they can be assigned and tracked as a unit — for example, the Azure Security Benchmark initiative bundles dozens of definitions.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/governance/policy/concepts/initiative-definition-structure","label":"Microsoft Learn — Azure Policy initiative definitions"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$True or False: An Azure Policy initiative is a collection of policy definitions grouped together to achieve a single overall compliance goal.$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A user must be able to assign Reader access to a resource group but should not be able to delete or modify resources in it. Which role assignment is most appropriate?$az104r$, $az104r$[{"id":"a","text":"Owner on the resource group"},{"id":"b","text":"Contributor on the resource group"},{"id":"c","text":"User Access Administrator on the resource group"},{"id":"d","text":"Reader on the resource group"}]$az104r$::jsonb, $az104r$["c"]$az104r$::jsonb, $az104r$User Access Administrator grants the ability to manage user access (role assignments) without granting permissions on the resources themselves. Owner gives full control; Contributor cannot manage access; Reader cannot assign roles.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/role-based-access-control/built-in-roles","label":"Microsoft Learn — Azure built-in roles"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A user must be able to assign Reader access to a resource group but should not be able to delete or modify resources in it. Which role assignment is most appropriate?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You want users to register their own authentication methods (phone, Authenticator app) without contacting IT to unlock their accounts after a password forget. Which feature should you enable?$az104r$, $az104r$[{"id":"a","text":"Conditional Access"},{"id":"b","text":"Self-service password reset (SSPR)"},{"id":"c","text":"Azure AD Connect"},{"id":"d","text":"Privileged Identity Management"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$SSPR lets users reset their own passwords after verifying their identity with registered methods, eliminating helpdesk tickets. CA enforces policies, AD Connect syncs from on-prem AD, and PIM is for privileged-role activation.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/authentication/concept-sspr-howitworks","label":"Microsoft Learn — Self-service password reset"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want users to register their own authentication methods (phone, Authenticator app) without contacting IT to unlock their accounts after a password forget. Which feature should you enable?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 1, $az104r$SINGLE$az104r$::"QType", $az104r$Which storage redundancy option synchronously replicates data three times across availability zones in a single Azure region?$az104r$, $az104r$[{"id":"a","text":"Locally redundant storage (LRS)"},{"id":"b","text":"Zone-redundant storage (ZRS)"},{"id":"c","text":"Geo-redundant storage (GRS)"},{"id":"d","text":"Geo-zone-redundant storage (GZRS)"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$ZRS synchronously replicates three copies across three availability zones in the primary region. LRS uses three replicas within a single datacenter; GRS adds an async secondary region copy of LRS; GZRS combines ZRS in primary plus async LRS in secondary.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-redundancy","label":"Microsoft Learn — Azure Storage redundancy"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which storage redundancy option synchronously replicates data three times across availability zones in a single Azure region?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You need to give a partner application read access to a single blob for 48 hours without sharing the storage account key. Which mechanism is most appropriate?$az104r$, $az104r$[{"id":"a","text":"Storage account access key"},{"id":"b","text":"A user-delegation SAS with read permission and 48-hour expiry"},{"id":"c","text":"Anonymous public read access on the container"},{"id":"d","text":"A Microsoft Entra service principal with Storage Account Contributor"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$A SAS (preferably user-delegation, signed with Entra credentials) gives time- and scope-limited access. Sharing the account key gives full control. Public read exposes the data to everyone. Storage Account Contributor grants management-plane rights, not scoped blob read.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-sas-overview","label":"Microsoft Learn — Grant limited access with shared access signatures"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You need to give a partner application read access to a single blob for 48 hours without sharing the storage account key. Which mechanism is most appropriate?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A storage account contains rarely accessed audit logs. Which blob access tier minimizes storage cost for data accessed less than once a year?$az104r$, $az104r$[{"id":"a","text":"Hot"},{"id":"b","text":"Cool"},{"id":"c","text":"Cold"},{"id":"d","text":"Archive"}]$az104r$::jsonb, $az104r$["d"]$az104r$::jsonb, $az104r$Archive is the lowest-cost tier and is intended for data rarely (or never) accessed, with rehydration latency of hours. Hot is for frequent access, Cool for at-least-30-day storage with occasional access, Cold for at-least-90-day storage with rarer access.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/blobs/access-tiers-overview","label":"Microsoft Learn — Access tiers for blob data"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A storage account contains rarely accessed audit logs. Which blob access tier minimizes storage cost for data accessed less than once a year?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You configure a blob lifecycle management policy to move blobs from Hot to Cool after 30 days of no modification and to Archive after 180 days. Which evaluation cadence does the platform use?$az104r$, $az104r$[{"id":"a","text":"Real-time on each write"},{"id":"b","text":"Every minute"},{"id":"c","text":"Once per day at the storage-account level"},{"id":"d","text":"Only when manually invoked"}]$az104r$::jsonb, $az104r$["c"]$az104r$::jsonb, $az104r$Lifecycle management policies run at most once per day on each storage account; that is why rules are based on age in days, not minutes. The cadence is documented and not user-configurable.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/blobs/lifecycle-management-overview","label":"Microsoft Learn — Optimize costs with lifecycle management"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You configure a blob lifecycle management policy to move blobs from Hot to Cool after 30 days of no modification and to Archive after 180 days. Which evaluation cadence does the platform use?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which feature lets you recover blobs that were deleted in the last 14 days without restoring from backup?$az104r$, $az104r$[{"id":"a","text":"Soft delete for blobs"},{"id":"b","text":"Cool tier rehydrate"},{"id":"c","text":"Storage account replication"},{"id":"d","text":"Storage Explorer undo"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Soft delete retains deleted blobs for a configurable retention period (default 7, up to 365 days) so they can be undeleted in place. Rehydrate changes a tier, replication is for redundancy, and Storage Explorer has no built-in undo.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/blobs/soft-delete-blob-overview","label":"Microsoft Learn — Soft delete for blobs"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which feature lets you recover blobs that were deleted in the last 14 days without restoring from backup?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You need to extend an on-prem Windows file share into Azure Files while keeping a local cache for fast access at the branch office. Which solution should you deploy?$az104r$, $az104r$[{"id":"a","text":"Azure File Sync with a server endpoint on the Windows Server"},{"id":"b","text":"AzCopy nightly upload"},{"id":"c","text":"Storage Explorer mounts"},{"id":"d","text":"Azure Import/Export"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Azure File Sync turns Windows Server into a fast cache of an Azure file share with cloud tiering for cold files. AzCopy is a one-way transfer tool, Storage Explorer is a desktop GUI, Import/Export ships physical disks.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/file-sync/file-sync-planning","label":"Microsoft Learn — Planning for an Azure File Sync deployment"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You need to extend an on-prem Windows file share into Azure Files while keeping a local cache for fast access at the branch office. Which solution should you deploy?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$MULTI$az104r$::"QType", $az104r$Select ALL services natively supported by an Azure Standard general-purpose v2 storage account.$az104r$, $az104r$[{"id":"a","text":"Blob storage"},{"id":"b","text":"File shares (SMB / NFS)"},{"id":"c","text":"Queue storage"},{"id":"d","text":"Azure SQL Database"}]$az104r$::jsonb, $az104r$["a","b","c"]$az104r$::jsonb, $az104r$General-purpose v2 accounts host blobs, files, queues, and tables in one account. Azure SQL Database is a separate PaaS service and is not a storage account service.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-account-overview","label":"Microsoft Learn — Storage account overview"},{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-account-overview#types-of-storage-accounts","label":"Microsoft Learn — Types of storage accounts"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Select ALL services natively supported by an Azure Standard general-purpose v2 storage account.$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A security review requires that no internet client can reach your storage account by default, but a specific VNet subnet must still be able to. Which configuration achieves this?$az104r$, $az104r$[{"id":"a","text":"Enable the firewall with \"Allow access from selected virtual networks\", and add the subnet via a service endpoint or private endpoint"},{"id":"b","text":"Rotate the storage account keys daily"},{"id":"c","text":"Set the storage account to Cool tier"},{"id":"d","text":"Disable HTTPS and allow only HTTP"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Storage firewalls deny by default when configured; you then permit specific VNets/subnets via service endpoints or private endpoints. Key rotation, tiering and disabling HTTPS do not restrict network reachability.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-network-security","label":"Microsoft Learn — Configure Azure Storage firewalls and virtual networks"},{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-private-endpoints","label":"Microsoft Learn — Use private endpoints for Azure Storage"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A security review requires that no internet client can reach your storage account by default, but a specific VNet subnet must still be able to. Which configuration achieves this?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You need to copy a 500 GB folder from an on-prem file server to Azure Blob Storage as efficiently as possible. Which tool is best suited?$az104r$, $az104r$[{"id":"a","text":"azcopy with the appropriate SAS or Entra credential"},{"id":"b","text":"Drag and drop in the Azure portal"},{"id":"c","text":"Cloud Shell tar"},{"id":"d","text":"Storage Account Keys Manage CLI"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$AzCopy is the high-throughput, multi-threaded data transfer tool optimized for large amounts of blob/file data. Portal upload is not suitable for hundreds of gigabytes; Cloud Shell tar is unrelated; the keys-manage CLI rotates keys.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-use-azcopy-v10","label":"Microsoft Learn — Get started with AzCopy"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You need to copy a 500 GB folder from an on-prem file server to Azure Blob Storage as efficiently as possible. Which tool is best suited?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A storage account access key was leaked. Which remediation invalidates the compromised key immediately?$az104r$, $az104r$[{"id":"a","text":"Rotate (regenerate) the affected key (key1 or key2) in the storage account"},{"id":"b","text":"Delete the storage account"},{"id":"c","text":"Set the storage account to read-only"},{"id":"d","text":"Disable Geo replication"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Regenerating the affected key immediately invalidates it. You typically keep two keys so apps can be migrated to the unrotated one before regenerating the compromised key. Deleting the account is destructive; read-only/replication settings do not invalidate keys.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-account-keys-manage","label":"Microsoft Learn — Manage storage account access keys"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A storage account access key was leaked. Which remediation invalidates the compromised key immediately?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which feature retains and protects every change to a blob by automatically maintaining previous versions when a write or delete occurs?$az104r$, $az104r$[{"id":"a","text":"Blob versioning"},{"id":"b","text":"Soft delete for containers"},{"id":"c","text":"Static website hosting"},{"id":"d","text":"Object replication"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Blob versioning automatically creates an immutable previous version on every write/delete so you can restore any prior state. Soft delete recovers deleted items; static websites serve content; object replication copies blobs across accounts.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/blobs/versioning-overview","label":"Microsoft Learn — Blob versioning"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which feature retains and protects every change to a blob by automatically maintaining previous versions when a write or delete occurs?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You want to ship 80 TB into Azure Blob Storage from an air-gapped datacenter with no fast WAN. Which option is purpose-built for this?$az104r$, $az104r$[{"id":"a","text":"Azure Import/Export with customer-supplied disks (or Azure Data Box)"},{"id":"b","text":"AzCopy over a 10 Mbps public internet link"},{"id":"c","text":"Azure Files SMB upload"},{"id":"d","text":"Storage Explorer drag and drop"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$For multi-TB offline transfer, Azure Import/Export (or Azure Data Box) ships physical media. Online tools (AzCopy, Storage Explorer, Files SMB) require sufficient bandwidth, which a 10 Mbps link cannot deliver in reasonable time.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/import-export/storage-import-export-service","label":"Microsoft Learn — What is Azure Import/Export service?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want to ship 80 TB into Azure Blob Storage from an air-gapped datacenter with no fast WAN. Which option is purpose-built for this?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 1, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure VM SLA is provided when two or more VMs are deployed across availability zones in the same region?$az104r$, $az104r$[{"id":"a","text":"99.9% single instance"},{"id":"b","text":"99.95% with availability set"},{"id":"c","text":"99.99% across availability zones"},{"id":"d","text":"100% always"}]$az104r$::jsonb, $az104r$["c"]$az104r$::jsonb, $az104r$Two or more VMs across Availability Zones in the same region deliver a 99.99% connectivity SLA. Single Premium SSD VMs are 99.9%; availability sets give 99.95%; no Azure SLA is 100%.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/reliability/availability-zones-overview","label":"Microsoft Learn — Availability zones"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure VM SLA is provided when two or more VMs are deployed across availability zones in the same region?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which managed disk type provides the highest IOPS and lowest latency for an I/O-intensive transactional workload?$az104r$, $az104r$[{"id":"a","text":"Standard HDD"},{"id":"b","text":"Standard SSD"},{"id":"c","text":"Premium SSD v2 (or Ultra Disk)"},{"id":"d","text":"Archive Disk"}]$az104r$::jsonb, $az104r$["c"]$az104r$::jsonb, $az104r$Premium SSD v2 and Ultra Disks deliver the highest sustained IOPS and lowest latency for I/O-intensive workloads (databases, SAP HANA). Standard HDD/SSD are lower-tier; "Archive Disk" is not a managed disk SKU.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/managed-disks-overview","label":"Microsoft Learn — Azure managed disks overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which managed disk type provides the highest IOPS and lowest latency for an I/O-intensive transactional workload?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You need to deploy 10 identical front-end VMs that can scale out to 50 based on CPU load and scale back in during quiet periods. Which Azure compute construct is purpose-built for this?$az104r$, $az104r$[{"id":"a","text":"A Virtual Machine Scale Set with autoscale rules"},{"id":"b","text":"An availability set with manual scaling"},{"id":"c","text":"Azure Functions Consumption plan"},{"id":"d","text":"Azure Batch pool"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$VM Scale Sets manage a pool of identical VMs with autoscale rules. Availability sets do not autoscale; Functions is serverless code, not generic VMs; Batch is for HPC job scheduling.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-machine-scale-sets/overview","label":"Microsoft Learn — Virtual Machine Scale Sets overview"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-machine-scale-sets/virtual-machine-scale-sets-autoscale-overview","label":"Microsoft Learn — Autoscale a VM scale set"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You need to deploy 10 identical front-end VMs that can scale out to 50 based on CPU load and scale back in during quiet periods. Which Azure compute construct is purpose-built for this?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure feature installs an agent into a VM after deployment to perform actions such as configuring antivirus, joining a domain, or running custom scripts?$az104r$, $az104r$[{"id":"a","text":"VM extensions (e.g., Custom Script Extension, DSC)"},{"id":"b","text":"Boot diagnostics"},{"id":"c","text":"Update Manager"},{"id":"d","text":"Azure Bastion"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$VM extensions are small management agents (CustomScriptExtension, DSC, MDE/AV, MSAV) that run post-deployment customizations. Boot diagnostics streams console output, Update Manager patches OS, Bastion provides RDP/SSH access.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/extensions/overview","label":"Microsoft Learn — Virtual machine extensions and features"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure feature installs an agent into a VM after deployment to perform actions such as configuring antivirus, joining a domain, or running custom scripts?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 3, $az104r$MULTI$az104r$::"QType", $az104r$Select ALL true statements about Azure availability sets.$az104r$, $az104r$[{"id":"a","text":"They distribute VMs across fault domains (separate racks/power) and update domains (rolling maintenance)."},{"id":"b","text":"They span multiple Azure regions for disaster recovery."},{"id":"c","text":"VMs in an availability set get a 99.95% connectivity SLA when at least two are deployed."},{"id":"d","text":"A single VM can be added to an availability set after deployment."}]$az104r$::jsonb, $az104r$["a","c"]$az104r$::jsonb, $az104r$Availability sets group VMs into FDs and UDs within a single datacenter/region for higher availability (99.95% with two or more VMs). They do not span regions, and an availability set must be specified at VM creation time — you cannot add an existing VM later.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/availability-set-overview","label":"Microsoft Learn — Availability sets overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Select ALL true statements about Azure availability sets.$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure service backs up Azure VMs to a Recovery Services vault with application-consistent snapshots?$az104r$, $az104r$[{"id":"a","text":"Azure Backup (VM backup)"},{"id":"b","text":"Azure Site Recovery (ASR)"},{"id":"c","text":"Storage account snapshots"},{"id":"d","text":"Azure Migrate"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Azure Backup performs scheduled, application-consistent VM backups to a Recovery Services vault. ASR replicates VMs for DR/failover. Storage snapshots are raw disk snapshots without VSS. Azure Migrate assesses on-prem servers for migration.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/backup/backup-azure-vms-introduction","label":"Microsoft Learn — Azure VM backup overview"},{"url":"https://learn.microsoft.com/en-us/azure/backup/backup-azure-recovery-services-vault-overview","label":"Microsoft Learn — Recovery Services vault overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure service backs up Azure VMs to a Recovery Services vault with application-consistent snapshots?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You want to replicate Azure VMs from East US to West US so that you can fail them over during a regional outage. Which service should you use?$az104r$, $az104r$[{"id":"a","text":"Azure Backup"},{"id":"b","text":"Azure Site Recovery"},{"id":"c","text":"Azure Migrate"},{"id":"d","text":"Storage account GRS"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Azure Site Recovery replicates VMs to a secondary region and orchestrates failover/failback for DR. Backup restores from snapshots (recovery, not failover). Migrate is for one-way migrations. GRS replicates blobs, not VMs.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/site-recovery/site-recovery-overview","label":"Microsoft Learn — About Azure Site Recovery"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want to replicate Azure VMs from East US to West US so that you can fail them over during a regional outage. Which service should you use?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure Resource Manager artifact is the declarative JSON file used to deploy infrastructure as code?$az104r$, $az104r$[{"id":"a","text":"ARM template"},{"id":"b","text":"Azure Policy initiative"},{"id":"c","text":"RBAC role definition"},{"id":"d","text":"Cosmos DB throughput definition"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$ARM templates are JSON files describing the resources to deploy and their properties; Bicep is a higher-level DSL that compiles to ARM JSON. Policies, RBAC roles and Cosmos throughput are different artifacts.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-resource-manager/management/overview","label":"Microsoft Learn — What is Azure Resource Manager?"},{"url":"https://learn.microsoft.com/en-us/azure/azure-resource-manager/templates/overview","label":"Microsoft Learn — ARM template overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure Resource Manager artifact is the declarative JSON file used to deploy infrastructure as code?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You want a cleaner, more concise DSL than ARM JSON for declarative deployments, with full ARM-feature parity. Which tool should you adopt?$az104r$, $az104r$[{"id":"a","text":"Bicep"},{"id":"b","text":"Azure PowerShell modules"},{"id":"c","text":"Azure CLI"},{"id":"d","text":"Terraform Cloud (third-party)"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Bicep is Microsoft's native DSL for ARM with first-class ARM parity and simpler syntax. PowerShell and CLI are imperative scripting tools. Terraform is third-party (and a valid option but not Microsoft's built-in DSL).$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-resource-manager/bicep/overview","label":"Microsoft Learn — What is Bicep?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want a cleaner, more concise DSL than ARM JSON for declarative deployments, with full ARM-feature parity. Which tool should you adopt?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You need to run a single container with a public IP for a short-lived batch job, without managing any cluster. Which service is the simplest fit?$az104r$, $az104r$[{"id":"a","text":"Azure Kubernetes Service"},{"id":"b","text":"Azure Container Instances"},{"id":"c","text":"Azure Functions Premium"},{"id":"d","text":"Azure App Service"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Azure Container Instances runs a container in seconds with a public IP and per-second billing, ideal for short-lived workloads. AKS adds Kubernetes complexity; Functions runs code, not arbitrary containers as a job; App Service is for web apps.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/container-instances/container-instances-overview","label":"Microsoft Learn — Azure Container Instances overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You need to run a single container with a public IP for a short-lived batch job, without managing any cluster. Which service is the simplest fit?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure service hosts private Docker container images with geo-replication and Microsoft Entra-integrated authentication?$az104r$, $az104r$[{"id":"a","text":"Azure Container Registry"},{"id":"b","text":"Azure Container Apps"},{"id":"c","text":"Azure DevOps Artifacts"},{"id":"d","text":"Azure Storage container"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Azure Container Registry (ACR) stores OCI/Docker images privately, supports geo-replication in Premium tier, and authenticates via Entra ID. Container Apps runs containers; DevOps Artifacts is for packages; Storage containers hold blobs, not images.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/container-registry/container-registry-intro","label":"Microsoft Learn — Azure Container Registry introduction"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure service hosts private Docker container images with geo-replication and Microsoft Entra-integrated authentication?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$In an App Service plan, which scaling action increases the SKU from S1 to P1v3 to provide more CPU and memory per instance?$az104r$, $az104r$[{"id":"a","text":"Scale out"},{"id":"b","text":"Scale up"},{"id":"c","text":"Autoscale by request count"},{"id":"d","text":"Always On"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Scale up changes the pricing tier (SKU) for more powerful instances. Scale out adds more instances of the current SKU. Autoscale rules trigger scale out. Always On keeps the app warm but does not change capacity.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/app-service/overview-hosting-plans","label":"Microsoft Learn — Azure App Service plan overview"},{"url":"https://learn.microsoft.com/en-us/azure/app-service/overview","label":"Microsoft Learn — Azure App Service overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$In an App Service plan, which scaling action increases the SKU from S1 to P1v3 to provide more CPU and memory per instance?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You deploy a Windows VM and need to RDP into it. Which inbound port must be allowed in the network security group on the VM's NIC or subnet?$az104r$, $az104r$[{"id":"a","text":"TCP 22"},{"id":"b","text":"TCP 3389"},{"id":"c","text":"TCP 443"},{"id":"d","text":"UDP 161"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$RDP uses TCP 3389. TCP 22 is SSH (for Linux), TCP 443 is HTTPS, UDP 161 is SNMP. For security, prefer Bastion or Just-In-Time access rather than opening 3389 to the internet.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/network-security-groups-overview","label":"Microsoft Learn — Network security groups"},{"url":"https://learn.microsoft.com/en-us/azure/bastion/bastion-overview","label":"Microsoft Learn — What is Azure Bastion?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You deploy a Windows VM and need to RDP into it. Which inbound port must be allowed in the network security group on the VM's NIC or subnet?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A new VM size shows "B2s". What does the "B" series indicate?$az104r$, $az104r$[{"id":"a","text":"Burstable VM with bankable CPU credits"},{"id":"b","text":"Bare-metal hardware"},{"id":"c","text":"Basic SKU with no SLA"},{"id":"d","text":"Big-data optimized"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$B-series are burstable VMs that earn CPU credits when idle and burst above baseline when needed; ideal for low-utilization workloads with occasional spikes. They are general-purpose, not bare-metal or big-data SKUs.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/sizes","label":"Microsoft Learn — Sizes for virtual machines in Azure"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A new VM size shows "B2s". What does the "B" series indicate?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You want to deploy a managed Kubernetes cluster where Microsoft manages the control plane and you pay only for worker nodes. Which Azure service is that?$az104r$, $az104r$[{"id":"a","text":"Azure Kubernetes Service"},{"id":"b","text":"Azure Container Instances"},{"id":"c","text":"Azure Service Fabric"},{"id":"d","text":"Azure Container Apps"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$AKS provides a managed Kubernetes control plane (free) and you pay only for the agent nodes. ACI is single-container, not Kubernetes. Service Fabric is a different microservices platform. Container Apps runs containers with KEDA-based scaling.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/aks/what-is-aks","label":"Microsoft Learn — Azure Kubernetes Service overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want to deploy a managed Kubernetes cluster where Microsoft manages the control plane and you pay only for worker nodes. Which Azure service is that?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 1, $az104r$SINGLE$az104r$::"QType", $az104r$What is the smallest subnet size you can create in an Azure virtual network?$az104r$, $az104r$[{"id":"a","text":"/24 (256 addresses)"},{"id":"b","text":"/29 (8 addresses, 3 usable)"},{"id":"c","text":"/30 (4 addresses, 1 usable)"},{"id":"d","text":"/32 (1 address)"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Azure reserves 5 addresses per subnet (network, gateway, two DNS, broadcast). The smallest supported subnet is /29 (8 addresses, 3 usable for resources). /30 and /32 are not supported.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/virtual-network-manage-subnet","label":"Microsoft Learn — Add, change, or delete a virtual network subnet"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$What is the smallest subnet size you can create in an Azure virtual network?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure construct lets two virtual networks in different regions communicate over the Microsoft backbone without a VPN gateway?$az104r$, $az104r$[{"id":"a","text":"Global VNet peering"},{"id":"b","text":"Local subnet peering"},{"id":"c","text":"ExpressRoute Direct"},{"id":"d","text":"Service endpoint"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Global VNet peering connects VNets across regions over the Microsoft backbone with low latency and high throughput, no gateway required. ExpressRoute is for on-prem connectivity, service endpoints are for PaaS access, "local subnet peering" is not a term.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/virtual-network-peering-overview","label":"Microsoft Learn — Virtual network peering"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure construct lets two virtual networks in different regions communicate over the Microsoft backbone without a VPN gateway?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You apply an NSG to both a subnet and a VM NIC in that subnet. How are the rules evaluated for inbound traffic?$az104r$, $az104r$[{"id":"a","text":"Only the NIC NSG is evaluated; the subnet NSG is ignored."},{"id":"b","text":"Inbound traffic must be allowed by both the subnet NSG and the NIC NSG."},{"id":"c","text":"Only the subnet NSG is evaluated; the NIC NSG is ignored."},{"id":"d","text":"The most permissive of the two NSGs is applied."}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$When both NSGs are attached, inbound traffic is evaluated against the subnet NSG first, then the NIC NSG; both must allow the traffic. Outbound is evaluated NIC then subnet. Either NSG can deny the flow.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/network-security-groups-overview","label":"Microsoft Learn — Network security groups"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You apply an NSG to both a subnet and a VM NIC in that subnet. How are the rules evaluated for inbound traffic?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which feature lets you reference a logical grouping like "WebServers" or "DbServers" inside NSG rules instead of explicit IP ranges?$az104r$, $az104r$[{"id":"a","text":"Application security groups"},{"id":"b","text":"Service tags"},{"id":"c","text":"Route tables"},{"id":"d","text":"Network virtual appliances"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Application Security Groups let you group VM NICs and reference the group in NSG rules so rules stay stable as IPs change. Service tags are Microsoft-managed (e.g., AzureCloud, Sql). Route tables direct traffic; NVAs are appliances.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/application-security-groups","label":"Microsoft Learn — Application security groups"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/network-security-groups-overview","label":"Microsoft Learn — Network security groups"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which feature lets you reference a logical grouping like "WebServers" or "DbServers" inside NSG rules instead of explicit IP ranges?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You need site-to-site connectivity from your on-prem datacenter to Azure with predictable bandwidth and private peering that does not traverse the public internet. Which option fits?$az104r$, $az104r$[{"id":"a","text":"Point-to-Site VPN"},{"id":"b","text":"Site-to-Site VPN over the public internet"},{"id":"c","text":"ExpressRoute"},{"id":"d","text":"VNet peering"}]$az104r$::jsonb, $az104r$["c"]$az104r$::jsonb, $az104r$ExpressRoute provides a dedicated, private connection through a connectivity provider with SLA-backed bandwidth. P2S VPN is for individual clients, S2S VPN traverses the public internet, and peering is between Azure VNets.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/expressroute/expressroute-introduction","label":"Microsoft Learn — What is Azure ExpressRoute?"},{"url":"https://learn.microsoft.com/en-us/azure/vpn-gateway/vpn-gateway-about-vpngateways","label":"Microsoft Learn — What is VPN Gateway?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You need site-to-site connectivity from your on-prem datacenter to Azure with predictable bandwidth and private peering that does not traverse the public internet. Which option fits?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure DNS feature provides name resolution for resources inside virtual networks using a private DNS zone like contoso.internal?$az104r$, $az104r$[{"id":"a","text":"Public Azure DNS zones"},{"id":"b","text":"Azure Private DNS zones"},{"id":"c","text":"Azure-provided DNS only"},{"id":"d","text":"Azure DNS Resolver outbound only"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Azure Private DNS hosts custom domain zones (e.g., contoso.internal) resolvable only within linked VNets. Public DNS is for internet zones. Azure-provided DNS gives default Azure-suffixed names. Private Resolver provides cross-tenant resolution.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/dns/private-dns-overview","label":"Microsoft Learn — What is Azure Private DNS?"},{"url":"https://learn.microsoft.com/en-us/azure/dns/dns-overview","label":"Microsoft Learn — What is Azure DNS?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure DNS feature provides name resolution for resources inside virtual networks using a private DNS zone like contoso.internal?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You need a Layer 7 load balancer that performs URL-based routing, SSL termination, and Web Application Firewall (WAF) for a regional app. Which service should you use?$az104r$, $az104r$[{"id":"a","text":"Azure Load Balancer (Standard)"},{"id":"b","text":"Azure Application Gateway with WAF"},{"id":"c","text":"Azure Front Door"},{"id":"d","text":"Traffic Manager"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Application Gateway is a regional Layer 7 load balancer with URL-based routing, SSL offload, and optional WAF. Azure Load Balancer is Layer 4. Front Door is global Layer 7 at the edge. Traffic Manager is DNS-based.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/application-gateway/overview","label":"Microsoft Learn — What is Azure Application Gateway?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You need a Layer 7 load balancer that performs URL-based routing, SSL termination, and Web Application Firewall (WAF) for a regional app. Which service should you use?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You want a globally distributed Layer 7 entry point with edge caching, WAF, and acceleration that routes to multiple regional backends. Which service?$az104r$, $az104r$[{"id":"a","text":"Application Gateway"},{"id":"b","text":"Azure Front Door"},{"id":"c","text":"VPN Gateway"},{"id":"d","text":"NAT Gateway"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Azure Front Door is the global, anycast-based Layer 7 entry point with edge caching, WAF, and acceleration. App Gateway is regional. VPN Gateway is for VPN connectivity. NAT Gateway provides outbound SNAT.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/frontdoor/front-door-overview","label":"Microsoft Learn — What is Azure Front Door?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want a globally distributed Layer 7 entry point with edge caching, WAF, and acceleration that routes to multiple regional backends. Which service?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A user-defined route (UDR) sends 0.0.0.0/0 to a firewall NVA. Where do you attach the route table to take effect?$az104r$, $az104r$[{"id":"a","text":"On the virtual network resource"},{"id":"b","text":"On the subnet that contains the VMs"},{"id":"c","text":"On the public IP address"},{"id":"d","text":"On the NSG"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Route tables are associated with subnets; traffic from any NIC in that subnet then uses the routes. They are not attached to VNets, public IPs, or NSGs.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/virtual-networks-udr-overview","label":"Microsoft Learn — Virtual network traffic routing"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A user-defined route (UDR) sends 0.0.0.0/0 to a firewall NVA. Where do you attach the route table to take effect?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You want admins to RDP/SSH to Azure VMs without exposing 3389/22 to the internet and without managing jump boxes. Which service should you use?$az104r$, $az104r$[{"id":"a","text":"Azure Bastion (deployed in the VNet)"},{"id":"b","text":"Azure Front Door"},{"id":"c","text":"NAT Gateway"},{"id":"d","text":"ExpressRoute"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Azure Bastion provides browser-based RDP/SSH over TLS without a public IP on the VM. Front Door is for HTTP(S) apps, NAT Gateway is for outbound SNAT, and ExpressRoute is private connectivity from on-prem.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/bastion/bastion-overview","label":"Microsoft Learn — What is Azure Bastion?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want admins to RDP/SSH to Azure VMs without exposing 3389/22 to the internet and without managing jump boxes. Which service should you use?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$MULTI$az104r$::"QType", $az104r$Select ALL valid SKUs of Azure Public IP addresses.$az104r$, $az104r$[{"id":"a","text":"Basic"},{"id":"b","text":"Standard"},{"id":"c","text":"Global"},{"id":"d","text":"Premium"}]$az104r$::jsonb, $az104r$["a","b","c"]$az104r$::jsonb, $az104r$Public IP SKUs are Basic, Standard, and Global (Standard zone-redundant). There is no "Premium" Public IP SKU. (Note: Basic is being retired but is still a valid SKU.)$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/ip-services/public-ip-addresses","label":"Microsoft Learn — Public IP addresses"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Select ALL valid SKUs of Azure Public IP addresses.$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$A VM in a subnet without a public IP needs reliable outbound connectivity to the internet for OS updates. Which service is recommended over default outbound SNAT?$az104r$, $az104r$[{"id":"a","text":"Azure NAT Gateway associated with the subnet"},{"id":"b","text":"Azure Bastion"},{"id":"c","text":"Application Gateway"},{"id":"d","text":"Service endpoint to Microsoft.Storage"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$NAT Gateway provides scalable, low-maintenance, dedicated outbound SNAT and is Microsoft's recommended outbound path. Bastion handles inbound RDP/SSH. App Gateway is inbound L7. Service endpoints are for PaaS connectivity, not generic internet egress.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/nat-gateway/nat-overview","label":"Microsoft Learn — What is Virtual Network NAT?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A VM in a subnet without a public IP needs reliable outbound connectivity to the internet for OS updates. Which service is recommended over default outbound SNAT?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure Load Balancer SKU is required to load-balance across availability zones?$az104r$, $az104r$[{"id":"a","text":"Basic Load Balancer"},{"id":"b","text":"Standard Load Balancer"},{"id":"c","text":"Gateway Load Balancer only"},{"id":"d","text":"Internal Load Balancer cannot use zones"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Only the Standard Load Balancer SKU supports availability zones (zone-redundant or zonal frontends). Basic does not. Gateway LB is a different scenario (NVA chaining). Internal LB can also be zonal.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/load-balancer/load-balancer-overview","label":"Microsoft Learn — What is Azure Load Balancer?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure Load Balancer SKU is required to load-balance across availability zones?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You configure a VNet-to-VNet peering between hub-vnet and spoke-vnet. By default, can VMs in spoke-vnet route through a firewall NVA in hub-vnet to reach the internet?$az104r$, $az104r$[{"id":"a","text":"Yes, peering automatically chains traffic through hub-vnet."},{"id":"b","text":"No — you must enable \"Allow forwarded traffic\" on the peering and add a UDR in spoke-vnet pointing 0.0.0.0/0 to the NVA."},{"id":"c","text":"Only when both VNets are in the same region."},{"id":"d","text":"Only with ExpressRoute."}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Peering does not automatically forward traffic between peers; you must enable "Allow forwarded traffic" (or "Allow gateway transit" for gateways) and define UDRs so traffic flows via the NVA. This is fundamental hub-spoke design.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/virtual-network-peering-overview","label":"Microsoft Learn — Virtual network peering"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/virtual-networks-udr-overview","label":"Microsoft Learn — Virtual network traffic routing"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You configure a VNet-to-VNet peering between hub-vnet and spoke-vnet. By default, can VMs in spoke-vnet route through a firewall NVA in hub-vnet to reach the internet?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Monitor and maintain Azure resources$az104r$, 1, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure Monitor data store holds rich, queryable log telemetry collected from resources, agents, and diagnostic settings?$az104r$, $az104r$[{"id":"a","text":"Log Analytics workspace"},{"id":"b","text":"Storage account blob container"},{"id":"c","text":"Azure SQL Database"},{"id":"d","text":"Cosmos DB account"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Log Analytics workspaces are the analytics store for Azure Monitor Logs, queryable with KQL. Storage accounts can archive logs but are not directly queryable. SQL and Cosmos are general databases, not native log stores.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/logs/log-analytics-workspace-overview","label":"Microsoft Learn — Log Analytics workspace overview"},{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/logs/data-platform-logs","label":"Microsoft Learn — Azure Monitor Logs overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure Monitor data store holds rich, queryable log telemetry collected from resources, agents, and diagnostic settings?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Monitor and maintain Azure resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure Monitor feature sends platform metrics, resource logs, and activity logs from an Azure resource to a destination such as a Log Analytics workspace or storage account?$az104r$, $az104r$[{"id":"a","text":"Diagnostic settings"},{"id":"b","text":"Service Health"},{"id":"c","text":"Action groups"},{"id":"d","text":"Resource locks"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Diagnostic settings route metrics and logs from individual resources to Log Analytics, Storage, or Event Hubs. Service Health reports Azure outages. Action groups send alert notifications. Locks prevent change/delete.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/essentials/diagnostic-settings","label":"Microsoft Learn — Diagnostic settings in Azure Monitor"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure Monitor feature sends platform metrics, resource logs, and activity logs from an Azure resource to a destination such as a Log Analytics workspace or storage account?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Monitor and maintain Azure resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You want to receive an email and a webhook when the average CPU of a VM exceeds 80% for 5 minutes. Which two Azure Monitor concepts must you configure?$az104r$, $az104r$[{"id":"a","text":"A metric alert rule and an action group"},{"id":"b","text":"A diagnostic setting and a backup policy"},{"id":"c","text":"A Service Health alert and a recovery vault"},{"id":"d","text":"A Conditional Access policy and an RBAC role"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$A metric alert rule defines the condition; an action group defines the notifications/automation to fire when the alert triggers. Diagnostic settings route logs, Service Health alerts cover Azure outages, and CA/RBAC are unrelated.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/alerts/alerts-overview","label":"Microsoft Learn — Overview of Azure Monitor alerts"},{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/alerts/action-groups","label":"Microsoft Learn — Action groups"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want to receive an email and a webhook when the average CPU of a VM exceeds 80% for 5 minutes. Which two Azure Monitor concepts must you configure?$az104r$);
