INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Monitor and maintain Azure resources$az104r$, 3, $az104r$MULTI$az104r$::"QType", $az104r$Select ALL true statements about Log Analytics workspaces.$az104r$, $az104r$[{"id":"a","text":"They are queried with the Kusto Query Language (KQL)."},{"id":"b","text":"Each workspace is associated with exactly one Azure region."},{"id":"c","text":"Data ingestion is free unless a daily cap is exceeded."},{"id":"d","text":"Workspaces support pricing tiers like Pay-As-You-Go and Commitment Tiers."}]$az104r$::jsonb, $az104r$["a","b","d"]$az104r$::jsonb, $az104r$Workspaces are regional, queried with KQL, and priced via Pay-As-You-Go or commitment tiers (per-GB ingestion). Data ingestion is NOT free; a daily cap stops ingestion only after the cap is hit.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/logs/log-analytics-workspace-overview","label":"Microsoft Learn — Log Analytics workspace overview"},{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/logs/data-platform-logs","label":"Microsoft Learn — Azure Monitor Logs overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Select ALL true statements about Log Analytics workspaces.$az104r$);
