INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Monitor and maintain Azure resources$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure Monitor data type is best suited for near-real-time, numeric, low-latency analytics (e.g., CPU% per minute over the last hour)?$az104r$, $az104r$[{"id":"a","text":"Logs"},{"id":"b","text":"Metrics"},{"id":"c","text":"Activity log"},{"id":"d","text":"Traces"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Metrics are lightweight, time-series numeric data optimized for near-real-time charting and alerting. Logs are richer but higher-latency. Activity log records control-plane operations. Traces are App Insights distributed traces.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/essentials/data-platform-metrics","label":"Microsoft Learn — Azure Monitor Metrics overview"},{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/overview","label":"Microsoft Learn — Azure Monitor overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure Monitor data type is best suited for near-real-time, numeric, low-latency analytics (e.g., CPU% per minute over the last hour)?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Monitor and maintain Azure resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A VM has been deleted. Where can you confirm WHO deleted it and WHEN?$az104r$, $az104r$[{"id":"a","text":"Azure Activity log for the subscription"},{"id":"b","text":"NSG flow logs"},{"id":"c","text":"Diagnostic settings logs on the VM"},{"id":"d","text":"Resource Health"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$The Activity log records control-plane operations like resource deletions, including the caller identity, timestamp, and status. Flow logs record network traffic; diagnostic logs are emitted by the resource; Resource Health shows availability.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/overview","label":"Microsoft Learn — Azure Monitor overview"},{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/essentials/diagnostic-settings","label":"Microsoft Learn — Diagnostic settings in Azure Monitor"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p1$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A VM has been deleted. Where can you confirm WHO deleted it and WHEN?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Microsoft Entra ID license tier is required to enable Conditional Access policies?$az104r$, $az104r$[{"id":"a","text":"Microsoft Entra ID Free"},{"id":"b","text":"Microsoft Entra ID P1 or higher"},{"id":"c","text":"Microsoft Entra ID Premium for Office 365 only"},{"id":"d","text":"No license is required; Conditional Access is in Free"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Conditional Access requires Microsoft Entra ID P1 (or P2). The Free tier does not include policy-based access controls. Security defaults (a coarse all-on baseline) are available without a paid tier.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"},{"url":"https://learn.microsoft.com/en-us/entra/fundamentals/whatis","label":"Microsoft Learn — What is Microsoft Entra ID?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Microsoft Entra ID license tier is required to enable Conditional Access policies?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You delete a user from Microsoft Entra ID by mistake. Within what default window can you restore it from the Deleted users blade?$az104r$, $az104r$[{"id":"a","text":"24 hours"},{"id":"b","text":"7 days"},{"id":"c","text":"30 days"},{"id":"d","text":"Forever"}]$az104r$::jsonb, $az104r$["c"]$az104r$::jsonb, $az104r$Deleted Entra ID users remain in a soft-deleted state for 30 days, during which they can be restored. After 30 days they are permanently purged.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/entra/fundamentals/how-to-create-delete-users","label":"Microsoft Learn — How to add or delete users in Microsoft Entra ID"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You delete a user from Microsoft Entra ID by mistake. Within what default window can you restore it from the Deleted users blade?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You want a script that runs on a VM to access Azure Key Vault without storing any secret in code. Which Entra ID feature solves this?$az104r$, $az104r$[{"id":"a","text":"System-assigned managed identity on the VM"},{"id":"b","text":"A shared service-principal certificate in the script"},{"id":"c","text":"Embedding a SAS token"},{"id":"d","text":"Storage account key in an environment variable"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$A system-assigned managed identity gives the VM an Entra ID identity that can be granted RBAC on Key Vault, so the SDK retrieves a token automatically — no secret in code. The other options embed secrets you must rotate manually.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/role-based-access-control/overview","label":"Microsoft Learn — What is Azure RBAC?"},{"url":"https://learn.microsoft.com/en-us/entra/fundamentals/whatis","label":"Microsoft Learn — What is Microsoft Entra ID?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want a script that runs on a VM to access Azure Key Vault without storing any secret in code. Which Entra ID feature solves this?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$A management group "Prod" has a deny-public-IP policy. A Contributor on a child subscription tries to create a VM with a public IP. What happens?$az104r$, $az104r$[{"id":"a","text":"The deployment succeeds because Contributor outranks Policy."},{"id":"b","text":"The deployment is denied at submission time by Azure Policy."},{"id":"c","text":"The deployment succeeds and the resource is marked non-compliant."},{"id":"d","text":"A Conditional Access prompt appears."}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Deny effect is enforced at request time, regardless of the requester's RBAC role. Azure Policy and RBAC operate on different axes: RBAC says "can you do this action?" while Policy enforces "what configurations are allowed?".$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/governance/policy/concepts/effect-basics","label":"Microsoft Learn — Understand Azure Policy effects"},{"url":"https://learn.microsoft.com/en-us/azure/governance/policy/overview","label":"Microsoft Learn — What is Azure Policy?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A management group "Prod" has a deny-public-IP policy. A Contributor on a child subscription tries to create a VM with a public IP. What happens?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$MULTI$az104r$::"QType", $az104r$Select ALL valid hierarchy levels at which an Azure Policy can be assigned.$az104r$, $az104r$[{"id":"a","text":"Management group"},{"id":"b","text":"Subscription"},{"id":"c","text":"Resource group"},{"id":"d","text":"Individual disk SKU"}]$az104r$::jsonb, $az104r$["a","b","c"]$az104r$::jsonb, $az104r$Policies assign at management group, subscription, or resource group scope, and inherit downward. Resource-level assignments are not supported; instead, policy effects apply when resources are created/modified within the assigned scope.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/governance/policy/overview","label":"Microsoft Learn — What is Azure Policy?"},{"url":"https://learn.microsoft.com/en-us/azure/governance/management-groups/overview","label":"Microsoft Learn — Organize your resources with management groups"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Select ALL valid hierarchy levels at which an Azure Policy can be assigned.$az104r$);
