INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A guest user invited via B2B keeps getting redirected to their home tenant for authentication. Where do they actually authenticate?$az104r$, $az104r$[{"id":"a","text":"Always in the resource (inviting) tenant"},{"id":"b","text":"In their home tenant; the resource tenant receives the issued token"},{"id":"c","text":"Only on Microsoft 365 portal"},{"id":"d","text":"They cannot authenticate without a synced password"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$B2B guests authenticate against their home tenant. The resource tenant trusts the issued token and applies its own access controls (RBAC, Conditional Access).$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/entra/external-id/what-is-b2b","label":"Microsoft Learn — B2B collaboration overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A guest user invited via B2B keeps getting redirected to their home tenant for authentication. Where do they actually authenticate?$az104r$);
