INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$TRUE_FALSE$az104r$::"QType", $az104r$True or False: Azure tags applied at a resource group are NOT automatically inherited by child resources.$az104r$, $az104r$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only when initiated via portal"},{"id":"d","text":"Only on management groups"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$True. Tags are not inherited automatically — child resources do not get parent tags. To enforce inheritance, use Azure Policy with the "Inherit a tag" modify effect.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-resource-manager/management/tag-resources","label":"Microsoft Learn — Use tags to organize your Azure resources"},{"url":"https://learn.microsoft.com/en-us/azure/governance/policy/concepts/effect-basics","label":"Microsoft Learn — Understand Azure Policy effects"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$True or False: Azure tags applied at a resource group are NOT automatically inherited by child resources.$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You need a single billing boundary that can hold multiple subscriptions for cost reporting and policy assignment. Which two structures help most?$az104r$, $az104r$[{"id":"a","text":"Management groups for policy + a Billing account/Enterprise enrollment for cost"},{"id":"b","text":"Resource groups for both billing and policy"},{"id":"c","text":"Tags for billing and resource locks for policy"},{"id":"d","text":"Public IPs and route tables"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Management groups organize subscriptions for governance/policy inheritance. Billing accounts (EA/MCA) aggregate spend across subscriptions for invoicing. Resource groups don't cross subscriptions; tags help allocate cost but don't enforce policy.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/governance/management-groups/overview","label":"Microsoft Learn — Organize your resources with management groups"},{"url":"https://learn.microsoft.com/en-us/azure/cost-management-billing/manage/create-subscription","label":"Microsoft Learn — Azure subscriptions"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You need a single billing boundary that can hold multiple subscriptions for cost reporting and policy assignment. Which two structures help most?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which storage account redundancy option provides the highest durability by combining zone redundancy in the primary region with asynchronous replication to a second region?$az104r$, $az104r$[{"id":"a","text":"LRS"},{"id":"b","text":"ZRS"},{"id":"c","text":"GRS"},{"id":"d","text":"GZRS"}]$az104r$::jsonb, $az104r$["d"]$az104r$::jsonb, $az104r$GZRS = ZRS in primary + async LRS in secondary, the highest durability and zone resilience. LRS is single-DC, ZRS is intra-region across zones, GRS is LRS + async secondary.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-redundancy","label":"Microsoft Learn — Azure Storage redundancy"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which storage account redundancy option provides the highest durability by combining zone redundancy in the primary region with asynchronous replication to a second region?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A storage account has read-access geo-redundant storage (RA-GRS). Which endpoint do you read from to access the secondary region?$az104r$, $az104r$[{"id":"a","text":"https://<account>.blob.core.windows.net"},{"id":"b","text":"https://<account>-secondary.blob.core.windows.net"},{"id":"c","text":"https://<account>.secondary.blob.core.windows.net"},{"id":"d","text":"https://secondary.<account>.blob.core.windows.net"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$RA-GRS exposes a secondary read-only endpoint at <account>-secondary.<service>.core.windows.net. The primary endpoint is read/write.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-redundancy","label":"Microsoft Learn — Azure Storage redundancy"},{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-account-overview","label":"Microsoft Learn — Storage account overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A storage account has read-access geo-redundant storage (RA-GRS). Which endpoint do you read from to access the secondary region?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure Files tier offers the lowest latency and is backed by SSD for transaction-heavy workloads?$az104r$, $az104r$[{"id":"a","text":"Standard (HDD)"},{"id":"b","text":"Premium (SSD)"},{"id":"c","text":"Archive (offline)"},{"id":"d","text":"Cool (object only)"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Azure Files Premium uses SSD on FileStorage accounts for low-latency, high-IOPS workloads. Standard runs on HDD. Archive and Cool are blob tiers, not file-share tiers.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/files/storage-files-introduction","label":"Microsoft Learn — What is Azure Files?"},{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-account-overview#types-of-storage-accounts","label":"Microsoft Learn — Types of storage accounts"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure Files tier offers the lowest latency and is backed by SSD for transaction-heavy workloads?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$Which SAS type can be revoked without rotating storage account keys because revocation is achieved by deleting an associated server-side policy?$az104r$, $az104r$[{"id":"a","text":"Account SAS"},{"id":"b","text":"Service SAS without a stored access policy"},{"id":"c","text":"Service SAS with a stored access policy"},{"id":"d","text":"User-delegation SAS only"}]$az104r$::jsonb, $az104r$["c"]$az104r$::jsonb, $az104r$A Service SAS bound to a stored access policy can be revoked by deleting/modifying the policy without rotating account keys. Account SAS and ad-hoc Service SAS require key rotation to invalidate.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-sas-overview","label":"Microsoft Learn — Grant limited access with shared access signatures"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which SAS type can be revoked without rotating storage account keys because revocation is achieved by deleting an associated server-side policy?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A blob is set to the Archive tier. What is required to read its contents?$az104r$, $az104r$[{"id":"a","text":"Nothing — Archive blobs are readable directly."},{"id":"b","text":"Rehydrate the blob to Hot or Cool first (can take hours)."},{"id":"c","text":"Move the blob to a different storage account."},{"id":"d","text":"Enable RA-GRS on the storage account."}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Archive blobs are offline and must be rehydrated to Hot or Cool tier (standard or high priority) before read. Rehydration can take hours. Cross-account moves do not bypass the offline state.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/blobs/access-tiers-overview","label":"Microsoft Learn — Access tiers for blob data"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A blob is set to the Archive tier. What is required to read its contents?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You want a hostname inside your VNet (e.g., contosobackups.privatelink.blob.core.windows.net) to resolve to a private IP for your storage account. Which feature should you configure?$az104r$, $az104r$[{"id":"a","text":"Service endpoint"},{"id":"b","text":"Private endpoint with a private DNS zone"},{"id":"c","text":"NSG with a service tag"},{"id":"d","text":"Public IP allow list"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$A private endpoint gives the storage account a NIC and private IP in your VNet, and the privatelink.blob.core.windows.net private DNS zone resolves the alias to that IP. Service endpoints keep traffic on the Azure backbone but still use the public endpoint name.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-private-endpoints","label":"Microsoft Learn — Use private endpoints for Azure Storage"},{"url":"https://learn.microsoft.com/en-us/azure/dns/private-dns-overview","label":"Microsoft Learn — What is Azure Private DNS?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want a hostname inside your VNet (e.g., contosobackups.privatelink.blob.core.windows.net) to resolve to a private IP for your storage account. Which feature should you configure?$az104r$);
