INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure Files identity option lets domain-joined Windows clients use Kerberos to authenticate to an SMB file share without storing storage account keys on the client?$az104r$, $az104r$[{"id":"a","text":"Anonymous access"},{"id":"b","text":"Storage account key prompt"},{"id":"c","text":"On-premises Active Directory Domain Services (AD DS) authentication for Azure Files"},{"id":"d","text":"SAS in the connection string"}]$az104r$::jsonb, $az104r$["c"]$az104r$::jsonb, $az104r$On-prem AD DS or Microsoft Entra Kerberos identity-based auth for Azure Files lets users sign in transparently with their AD credentials. Other options either expose secrets or skip auth entirely.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/files/storage-files-introduction","label":"Microsoft Learn — What is Azure Files?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure Files identity option lets domain-joined Windows clients use Kerberos to authenticate to an SMB file share without storing storage account keys on the client?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A scheduled job needs to upload 5 GB nightly to a blob container from an Azure VM. Which authentication is most secure and key-free?$az104r$, $az104r$[{"id":"a","text":"Hard-coded storage account key"},{"id":"b","text":"Azure CLI azcopy login using the VM's managed identity, plus Storage Blob Data Contributor role"},{"id":"c","text":"SAS token in a config file checked into source"},{"id":"d","text":"Anonymous container"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Managed identity + RBAC role (Storage Blob Data Contributor) lets AzCopy authenticate without secrets. Hard-coded keys and committed SAS tokens are insecure; anonymous containers leak data.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-use-azcopy-v10","label":"Microsoft Learn — Get started with AzCopy"},{"url":"https://learn.microsoft.com/en-us/azure/role-based-access-control/overview","label":"Microsoft Learn — What is Azure RBAC?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A scheduled job needs to upload 5 GB nightly to a blob container from an Azure VM. Which authentication is most secure and key-free?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure feature gives a single namespace across multiple Azure Files shares and Windows Server endpoints, with cloud tiering of cold files?$az104r$, $az104r$[{"id":"a","text":"Azure File Sync"},{"id":"b","text":"AzCopy sync"},{"id":"c","text":"Storage account replication"},{"id":"d","text":"Cool blob tier"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Azure File Sync turns Windows Server into a fast local cache of an Azure file share, with cloud tiering to keep only hot files on disk. The others do not provide a unified namespace.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/file-sync/file-sync-planning","label":"Microsoft Learn — Planning for an Azure File Sync deployment"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure feature gives a single namespace across multiple Azure Files shares and Windows Server endpoints, with cloud tiering of cold files?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$A user can read public blobs without authenticating, but you want to disable anonymous public access account-wide. Where do you set this?$az104r$, $az104r$[{"id":"a","text":"Storage account > Configuration > \"Allow Blob anonymous access\" toggle (set to Disabled)"},{"id":"b","text":"Each container individually only"},{"id":"c","text":"NSG attached to the storage account"},{"id":"d","text":"Conditional Access policy targeting the storage account"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$The account-level toggle "Allow Blob anonymous access" overrides container-level public access settings. Disabling it blocks all anonymous reads regardless of container settings.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-account-overview","label":"Microsoft Learn — Storage account overview"},{"url":"https://learn.microsoft.com/en-us/azure/storage/blobs/storage-blobs-introduction","label":"Microsoft Learn — Introduction to Azure Blob Storage"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A user can read public blobs without authenticating, but you want to disable anonymous public access account-wide. Where do you set this?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure tool gives a GUI to upload, download, and inspect blobs/files/queues/tables from a desktop?$az104r$, $az104r$[{"id":"a","text":"Azure Storage Explorer"},{"id":"b","text":"Azure Monitor"},{"id":"c","text":"Cosmos DB Emulator"},{"id":"d","text":"Network Watcher"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Azure Storage Explorer is a free cross-platform desktop GUI for storage management. The others are unrelated services.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/storage-explorer/vs-azure-tools-storage-manage-with-storage-explorer","label":"Microsoft Learn — Storage Explorer overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure tool gives a GUI to upload, download, and inspect blobs/files/queues/tables from a desktop?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A VM is sized D4s_v5. What does the "s" suffix indicate?$az104r$, $az104r$[{"id":"a","text":"Spot-eligible pricing"},{"id":"b","text":"Premium Storage capable (supports premium SSD disks)"},{"id":"c","text":"Smaller memory footprint"},{"id":"d","text":"Single-tenant hardware"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$The "s" suffix indicates Premium Storage capability (can attach premium SSD disks). Spot pricing is a separate purchase option set at deployment. Memory and tenancy are not encoded by "s".$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/sizes","label":"Microsoft Learn — Sizes for virtual machines in Azure"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/managed-disks-overview","label":"Microsoft Learn — Azure managed disks overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A VM is sized D4s_v5. What does the "s" suffix indicate?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You need to deploy a stateless workload on cheap, preemptable VMs that can be reclaimed by Azure. Which purchasing option fits?$az104r$, $az104r$[{"id":"a","text":"Reserved instances"},{"id":"b","text":"Azure Hybrid Benefit"},{"id":"c","text":"Spot VMs"},{"id":"d","text":"Dedicated host"}]$az104r$::jsonb, $az104r$["c"]$az104r$::jsonb, $az104r$Spot VMs use spare Azure capacity at deep discounts but can be evicted on 30-second notice. Reserved instances commit to long-term capacity for discount. Azure Hybrid Benefit is licensing. Dedicated host is single-tenant hardware.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/sizes","label":"Microsoft Learn — Sizes for virtual machines in Azure"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/overview","label":"Microsoft Learn — Virtual machines in Azure"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You need to deploy a stateless workload on cheap, preemptable VMs that can be reclaimed by Azure. Which purchasing option fits?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You build a Bicep template with parameters for SKU and region. Which command deploys it to a resource group?$az104r$, $az104r$[{"id":"a","text":"az deployment group create --resource-group rg --template-file main.bicep --parameters ..."},{"id":"b","text":"az vm bicep deploy"},{"id":"c","text":"bicep build && az run"},{"id":"d","text":"docker compose up"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$`az deployment group create` deploys an ARM/Bicep template at resource group scope. There is no `az vm bicep deploy`; `bicep build` only compiles; `docker compose` is for local containers.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-resource-manager/bicep/overview","label":"Microsoft Learn — What is Bicep?"},{"url":"https://learn.microsoft.com/en-us/azure/azure-resource-manager/management/overview","label":"Microsoft Learn — What is Azure Resource Manager?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You build a Bicep template with parameters for SKU and region. Which command deploys it to a resource group?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$A VM Scale Set has an autoscale rule "scale out by 2 when average CPU > 70% for 5 minutes". Which Azure Monitor concept evaluates the metric and triggers the action?$az104r$, $az104r$[{"id":"a","text":"Autoscale settings backed by Azure Monitor metrics"},{"id":"b","text":"Action group"},{"id":"c","text":"Log Analytics alert"},{"id":"d","text":"Diagnostic settings"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$VMSS autoscale uses Azure Monitor autoscale settings against metric thresholds. Action groups deliver alert notifications. Logs alerts query KQL. Diagnostic settings only route telemetry.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-machine-scale-sets/virtual-machine-scale-sets-autoscale-overview","label":"Microsoft Learn — Autoscale a VM scale set"},{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/essentials/data-platform-metrics","label":"Microsoft Learn — Azure Monitor Metrics overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A VM Scale Set has an autoscale rule "scale out by 2 when average CPU > 70% for 5 minutes". Which Azure Monitor concept evaluates the metric and triggers the action?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which feature reduces VM cost when you commit to 1- or 3-year usage of a particular VM size and region?$az104r$, $az104r$[{"id":"a","text":"Reserved Instances"},{"id":"b","text":"Spot pricing"},{"id":"c","text":"Hybrid Benefit"},{"id":"d","text":"Pay-as-you-go"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Reserved Instances offer up to ~72% off vs. PAYG by committing for 1 or 3 years in a specific region/size family. Spot is preemptable, Hybrid Benefit reuses on-prem licenses, PAYG is the default.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/sizes","label":"Microsoft Learn — Sizes for virtual machines in Azure"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which feature reduces VM cost when you commit to 1- or 3-year usage of a particular VM size and region?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 3, $az104r$MULTI$az104r$::"QType", $az104r$Select ALL true statements about Azure VM disk encryption.$az104r$, $az104r$[{"id":"a","text":"Azure Disk Encryption (ADE) encrypts OS and data disks using BitLocker (Windows) or DM-Crypt (Linux) with keys in Key Vault."},{"id":"b","text":"Managed disks are encrypted at rest by default with platform-managed keys."},{"id":"c","text":"Customer-managed keys (CMK) can be used in place of platform-managed keys for managed disks."},{"id":"d","text":"Encryption requires the VM to be a P-series GPU SKU."}]$az104r$::jsonb, $az104r$["a","b","c"]$az104r$::jsonb, $az104r$Managed disks are encrypted at rest by default; CMK is supported; ADE adds in-guest encryption. Encryption is not gated on any specific GPU/CPU SKU.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/managed-disks-overview","label":"Microsoft Learn — Azure managed disks overview"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/overview","label":"Microsoft Learn — Virtual machines in Azure"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Select ALL true statements about Azure VM disk encryption.$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You want to deploy a containerized web app that auto-scales to zero when idle and supports KEDA event-driven scaling. Which Azure service is purpose-built for this?$az104r$, $az104r$[{"id":"a","text":"Azure Container Apps"},{"id":"b","text":"Azure Kubernetes Service"},{"id":"c","text":"Azure Container Instances"},{"id":"d","text":"Azure App Service Free tier"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Azure Container Apps offers serverless containers with KEDA-based event scaling, including scale-to-zero. AKS is full Kubernetes you manage; ACI runs a single container without elastic scale; App Service is for code-based web apps.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/aks/what-is-aks","label":"Microsoft Learn — Azure Kubernetes Service overview"},{"url":"https://learn.microsoft.com/en-us/azure/app-service/overview","label":"Microsoft Learn — Azure App Service overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want to deploy a containerized web app that auto-scales to zero when idle and supports KEDA event-driven scaling. Which Azure service is purpose-built for this?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which feature allows multiple App Service apps to share compute and is the unit of scale/pricing?$az104r$, $az104r$[{"id":"a","text":"App Service plan"},{"id":"b","text":"App Service slot"},{"id":"c","text":"App Service Environment v3 only"},{"id":"d","text":"Functions Premium plan only"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$An App Service plan defines the SKU, instance count, and OS that hosts one or more apps. Slots are deployment targets within an app; ASE v3 is a dedicated isolated plan flavor. The plan is the unit of scale and pricing.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/app-service/overview-hosting-plans","label":"Microsoft Learn — Azure App Service plan overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which feature allows multiple App Service apps to share compute and is the unit of scale/pricing?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You need to swap a staging deployment slot into production with zero-downtime. Which App Service feature gives you this?$az104r$, $az104r$[{"id":"a","text":"Deployment slot swap (with preview if needed)"},{"id":"b","text":"A blue-green script using Storage queues"},{"id":"c","text":"Manual scale-out"},{"id":"d","text":"WebJobs"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$App Service deployment slots support zero-downtime swap, including a preview to validate the warmed-up slot before completing the swap. The other options do not provide that capability.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/app-service/overview","label":"Microsoft Learn — Azure App Service overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You need to swap a staging deployment slot into production with zero-downtime. Which App Service feature gives you this?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You've published a Docker image to ACR and want App Service to pull and run it. Which feature/configuration is needed?$az104r$, $az104r$[{"id":"a","text":"Configure the App Service for a custom container and grant it AcrPull on the registry (managed identity recommended)"},{"id":"b","text":"Copy the image into the App Service runtime ZIP"},{"id":"c","text":"Use Azure Functions instead — App Service cannot run containers"},{"id":"d","text":"Mount the registry as a file share"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$App Service for containers pulls images from ACR using credentials or, preferably, the app's managed identity granted AcrPull. Functions can also run containers but is not required.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/app-service/overview","label":"Microsoft Learn — Azure App Service overview"},{"url":"https://learn.microsoft.com/en-us/azure/container-registry/container-registry-intro","label":"Microsoft Learn — Azure Container Registry introduction"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You've published a Docker image to ACR and want App Service to pull and run it. Which feature/configuration is needed?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure Backup tier setting determines whether VM backups can survive accidental deletion by ransomware actors?$az104r$, $az104r$[{"id":"a","text":"Soft delete / immutable vault settings on the Recovery Services vault"},{"id":"b","text":"GRS replication for blobs only"},{"id":"c","text":"NSG allow-list to the vault"},{"id":"d","text":"Spot eviction policy"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Soft delete (and immutable vault settings) protect backup recovery points from accidental or malicious deletion by retaining them in a soft-deleted state for a configurable period.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/backup/backup-azure-vms-introduction","label":"Microsoft Learn — Azure VM backup overview"},{"url":"https://learn.microsoft.com/en-us/azure/backup/backup-azure-recovery-services-vault-overview","label":"Microsoft Learn — Recovery Services vault overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure Backup tier setting determines whether VM backups can survive accidental deletion by ransomware actors?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You need to extend an on-prem Hyper-V VM into Azure for DR with replication and orchestrated failover. Which service?$az104r$, $az104r$[{"id":"a","text":"Azure Site Recovery (ASR)"},{"id":"b","text":"Azure Backup (VM workload)"},{"id":"c","text":"Azure Migrate (Server Assessment only)"},{"id":"d","text":"Azure File Sync"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Azure Site Recovery replicates on-prem VMs (Hyper-V, VMware, physical) to Azure and orchestrates failover and failback. Backup restores files/VMs; Migrate is one-way migration; File Sync is for file shares.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/site-recovery/site-recovery-overview","label":"Microsoft Learn — About Azure Site Recovery"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You need to extend an on-prem Hyper-V VM into Azure for DR with replication and orchestrated failover. Which service?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A Windows VM needs to join an Azure-hosted Microsoft Entra Domain Services managed domain. Which subnet placement is required?$az104r$, $az104r$[{"id":"a","text":"Same VNet as the Entra Domain Services managed domain, or a peered VNet with DNS pointing to the domain controllers"},{"id":"b","text":"A subnet without an NSG"},{"id":"c","text":"A subnet with a public IP gateway"},{"id":"d","text":"The default GatewaySubnet"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$VMs must reach the managed domain DCs via a connected VNet (same VNet or peered) and use the AAD DS DCs as DNS. NSG and gateway are not the determining factors.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/virtual-networks-overview","label":"Microsoft Learn — What is Azure Virtual Network?"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/overview","label":"Microsoft Learn — Virtual machines in Azure"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A Windows VM needs to join an Azure-hosted Microsoft Entra Domain Services managed domain. Which subnet placement is required?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which option lets a VM Scale Set automatically replace unhealthy instances based on Application Gateway health probes?$az104r$, $az104r$[{"id":"a","text":"Automatic instance repair"},{"id":"b","text":"Manual scale-out only"},{"id":"c","text":"Static placement groups"},{"id":"d","text":"Spot eviction policy"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Automatic instance repair on VMSS uses the load balancer or App Gateway health probe state to delete and reprovision unhealthy instances. Static placement and scale-out alone do not heal instances.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-machine-scale-sets/overview","label":"Microsoft Learn — Virtual Machine Scale Sets overview"},{"url":"https://learn.microsoft.com/en-us/azure/application-gateway/overview","label":"Microsoft Learn — What is Azure Application Gateway?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which option lets a VM Scale Set automatically replace unhealthy instances based on Application Gateway health probes?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$A VM is running but you cannot connect via RDP. Which Azure tool views the VM's console output to diagnose boot or OS issues?$az104r$, $az104r$[{"id":"a","text":"Boot diagnostics (serial console + screenshot)"},{"id":"b","text":"Update Manager"},{"id":"c","text":"Application Insights"},{"id":"d","text":"Cloud Shell only"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Boot diagnostics streams the VM console and shows a screenshot to diagnose boot/network/login failures. Update Manager and App Insights do not show OS console; Cloud Shell is an in-portal terminal.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/extensions/overview","label":"Microsoft Learn — Virtual machine extensions and features"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/overview","label":"Microsoft Learn — Virtual machines in Azure"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A VM is running but you cannot connect via RDP. Which Azure tool views the VM's console output to diagnose boot or OS issues?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Two VNets in the same region are peered. Which statement is true about latency and bandwidth between them?$az104r$, $az104r$[{"id":"a","text":"Traffic transits the public internet by default."},{"id":"b","text":"Traffic stays on the Microsoft backbone with low latency and high bandwidth."},{"id":"c","text":"It requires a VPN gateway in each VNet."},{"id":"d","text":"It requires ExpressRoute."}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$VNet peering uses the Microsoft backbone — no gateway, no public internet, low latency, and high bandwidth. Gateways or ExpressRoute are not required for peering.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/virtual-network-peering-overview","label":"Microsoft Learn — Virtual network peering"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Two VNets in the same region are peered. Which statement is true about latency and bandwidth between them?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You want to allow inbound TCP 443 to a single VM only from the Azure Front Door service. Which service tag should you reference in your NSG rule?$az104r$, $az104r$[{"id":"a","text":"AzureFrontDoor.Backend"},{"id":"b","text":"AzureCloud"},{"id":"c","text":"Internet"},{"id":"d","text":"VirtualNetwork"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$AzureFrontDoor.Backend is the service tag for Front Door's backend IPs. AzureCloud covers all Azure IPs (too broad), Internet is global, VirtualNetwork is internal.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/frontdoor/front-door-overview","label":"Microsoft Learn — What is Azure Front Door?"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/network-security-groups-overview","label":"Microsoft Learn — Network security groups"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want to allow inbound TCP 443 to a single VM only from the Azure Front Door service. Which service tag should you reference in your NSG rule?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure Load Balancer type provides public frontend IPs to distribute internet traffic to VMs in a VNet?$az104r$, $az104r$[{"id":"a","text":"Public Load Balancer"},{"id":"b","text":"Internal Load Balancer"},{"id":"c","text":"Gateway Load Balancer"},{"id":"d","text":"Cross-region Load Balancer only"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$A Public Load Balancer has a public frontend IP and distributes inbound internet traffic. Internal LBs use private frontends within a VNet. Gateway LB chains traffic to NVAs.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/load-balancer/load-balancer-overview","label":"Microsoft Learn — What is Azure Load Balancer?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure Load Balancer type provides public frontend IPs to distribute internet traffic to VMs in a VNet?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You need a VPN connection from a remote engineer's laptop to an Azure VNet. Which type of VPN should you configure?$az104r$, $az104r$[{"id":"a","text":"Site-to-Site (S2S) VPN"},{"id":"b","text":"Point-to-Site (P2S) VPN"},{"id":"c","text":"ExpressRoute Direct"},{"id":"d","text":"VNet peering"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Point-to-Site VPN connects a single client to Azure over an SSTP, OpenVPN, or IKEv2 tunnel. S2S connects whole networks. ExpressRoute is private connectivity for sites, not individual laptops. Peering is between Azure VNets.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/vpn-gateway/vpn-gateway-about-vpngateways","label":"Microsoft Learn — What is VPN Gateway?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You need a VPN connection from a remote engineer's laptop to an Azure VNet. Which type of VPN should you configure?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A subnet must use a network virtual appliance (NVA) for inspection of egress traffic. Which two configurations are required?$az104r$, $az104r$[{"id":"a","text":"Enable IP forwarding on the NVA NIC and a UDR on the subnet pointing 0.0.0.0/0 to the NVA"},{"id":"b","text":"A delete lock on the resource group"},{"id":"c","text":"Sites-to-Sites VPN between the NVA and the subnet"},{"id":"d","text":"Tags on the NVA equal to \"firewall\""}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$The NVA NIC must allow IP forwarding so it can forward packets, and the subnet must have a UDR sending traffic to the NVA's IP. Locks and tags do not affect routing.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/virtual-networks-udr-overview","label":"Microsoft Learn — Virtual network traffic routing"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/network-security-groups-overview","label":"Microsoft Learn — Network security groups"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A subnet must use a network virtual appliance (NVA) for inspection of egress traffic. Which two configurations are required?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure DNS feature lets external clients on the internet resolve a public domain like contoso.com hosted in Azure?$az104r$, $az104r$[{"id":"a","text":"Azure Public DNS zone"},{"id":"b","text":"Azure Private DNS zone"},{"id":"c","text":"Azure DNS Private Resolver"},{"id":"d","text":"Reverse DNS only"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Azure Public DNS hosts publicly resolvable zones. Private DNS is for VNet-only resolution. Private Resolver bridges on-prem to private zones.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/dns/dns-overview","label":"Microsoft Learn — What is Azure DNS?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure DNS feature lets external clients on the internet resolve a public domain like contoso.com hosted in Azure?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$A VM's NIC is in a subnet that is associated with a route table where 0.0.0.0/0 routes to a firewall. The VM also has a public IP. Which traffic uses the public IP?$az104r$, $az104r$[{"id":"a","text":"All outbound and inbound traffic uses the public IP unconditionally."},{"id":"b","text":"Inbound to the public IP still arrives directly, but outbound traffic follows the UDR through the firewall, not the public IP."},{"id":"c","text":"No traffic uses the public IP because the UDR overrides it."},{"id":"d","text":"Only ICMP traffic uses the public IP."}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$The UDR controls outbound paths only; outbound traffic now goes via the firewall. Inbound to a public IP still reaches the VM directly (subject to NSGs). Public IPs are not "overridden".$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/virtual-networks-udr-overview","label":"Microsoft Learn — Virtual network traffic routing"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/ip-services/public-ip-addresses","label":"Microsoft Learn — Public IP addresses"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A VM's NIC is in a subnet that is associated with a route table where 0.0.0.0/0 routes to a firewall. The VM also has a public IP. Which traffic uses the public IP?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You want to allow only members of a specific Microsoft Entra group to authenticate to a P2S VPN connection. Which authentication type should you select?$az104r$, $az104r$[{"id":"a","text":"Microsoft Entra ID authentication for VPN"},{"id":"b","text":"Pre-shared key (PSK) only"},{"id":"c","text":"Certificate-based with self-signed cert"},{"id":"d","text":"Anonymous"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Entra ID authentication for VPN supports Conditional Access and group-based access. PSKs and self-signed certs are not group-aware; anonymous defeats the purpose.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/vpn-gateway/vpn-gateway-about-vpngateways","label":"Microsoft Learn — What is VPN Gateway?"},{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want to allow only members of a specific Microsoft Entra group to authenticate to a P2S VPN connection. Which authentication type should you select?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which port and protocol does the Standard Azure Load Balancer use for HTTP health probes?$az104r$, $az104r$[{"id":"a","text":"TCP 22"},{"id":"b","text":"TCP 80 (configurable) for HTTP probes; HTTPS probe also supported"},{"id":"c","text":"UDP 53"},{"id":"d","text":"ICMP only"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Health probes can be configured for HTTP/HTTPS/TCP on any port; HTTP probe defaults are configurable. ICMP is not supported by Standard LB probes.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/load-balancer/load-balancer-overview","label":"Microsoft Learn — What is Azure Load Balancer?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which port and protocol does the Standard Azure Load Balancer use for HTTP health probes?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You need a hub-and-spoke topology with centralized firewall and on-prem connectivity. Which Azure service is purpose-built to host the hub with managed routing and SD-WAN integrations?$az104r$, $az104r$[{"id":"a","text":"Azure Virtual WAN"},{"id":"b","text":"Azure App Gateway"},{"id":"c","text":"Azure Front Door"},{"id":"d","text":"Traffic Manager"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Azure Virtual WAN provides a managed hub-and-spoke fabric with VPN, ExpressRoute, SD-WAN, and firewall integration. App Gateway is L7 in-region; Front Door is global L7; Traffic Manager is DNS-based.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/virtual-networks-overview","label":"Microsoft Learn — What is Azure Virtual Network?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You need a hub-and-spoke topology with centralized firewall and on-prem connectivity. Which Azure service is purpose-built to host the hub with managed routing and SD-WAN integrations?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$MULTI$az104r$::"QType", $az104r$Select ALL true statements about NSG rules.$az104r$, $az104r$[{"id":"a","text":"Rules are processed by priority, lowest number first; the first matching rule wins."},{"id":"b","text":"NSG rules support stateful connection tracking for return traffic."},{"id":"c","text":"You can use service tags like Sql or Storage as source or destination instead of explicit IPs."},{"id":"d","text":"NSGs perform deep packet inspection of HTTPS payloads."}]$az104r$::jsonb, $az104r$["a","b","c"]$az104r$::jsonb, $az104r$NSG rules are evaluated by priority, are stateful, and accept service tags. They do NOT do deep packet inspection — they are 5-tuple stateful filters. DPI is a feature of Azure Firewall/WAF/NVAs.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/network-security-groups-overview","label":"Microsoft Learn — Network security groups"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Select ALL true statements about NSG rules.$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A web app needs WAF protection for OWASP Top 10. The team chose Application Gateway. Which SKU and tier include WAF?$az104r$, $az104r$[{"id":"a","text":"Application Gateway WAF_v2"},{"id":"b","text":"Application Gateway Standard_v2 only"},{"id":"c","text":"Standard Load Balancer"},{"id":"d","text":"Azure Bastion"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$WAF_v2 is the App Gateway SKU that includes Web Application Firewall capabilities (Core Rule Set, custom rules, geo-filter). Standard_v2 omits WAF. LB and Bastion do not provide WAF.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/application-gateway/overview","label":"Microsoft Learn — What is Azure Application Gateway?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A web app needs WAF protection for OWASP Top 10. The team chose Application Gateway. Which SKU and tier include WAF?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You enable virtual network peering between VNetA and VNetB. Can VMs in VNetA reach VMs in VNetC, which is peered only to VNetB?$az104r$, $az104r$[{"id":"a","text":"Yes, peering is transitive by default."},{"id":"b","text":"No, VNet peering is non-transitive; you must enable forwarded traffic and route via an NVA/gateway, or directly peer VNetA and VNetC."},{"id":"c","text":"Only if all three VNets are in the same region."},{"id":"d","text":"Only with ExpressRoute on each."}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$VNet peering is non-transitive. To enable VNetA-VNetC traffic via VNetB, you must enable "Allow forwarded traffic", route traffic through an NVA/gateway in VNetB, or add a direct peering.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/virtual-network-peering-overview","label":"Microsoft Learn — Virtual network peering"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/virtual-networks-udr-overview","label":"Microsoft Learn — Virtual network traffic routing"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You enable virtual network peering between VNetA and VNetB. Can VMs in VNetA reach VMs in VNetC, which is peered only to VNetB?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure service blocks DDoS attacks on public IPs with adaptive tuning and tied to Azure Monitor alerting?$az104r$, $az104r$[{"id":"a","text":"Azure DDoS Protection (Network/IP Protection plans)"},{"id":"b","text":"Network Watcher"},{"id":"c","text":"Azure Firewall only"},{"id":"d","text":"Front Door rate limiting only"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Azure DDoS Protection (Network or IP Protection plans) extends the always-on infrastructure baseline with adaptive tuning, telemetry, and alerts. Network Watcher is diagnostics; Firewall/Front Door provide separate L4-L7 protections.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/ip-services/public-ip-addresses","label":"Microsoft Learn — Public IP addresses"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/virtual-networks-overview","label":"Microsoft Learn — What is Azure Virtual Network?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure service blocks DDoS attacks on public IPs with adaptive tuning and tied to Azure Monitor alerting?$az104r$);
