INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Monitor and maintain Azure resources$az104r$, 3, $az104r$MULTI$az104r$::"QType", $az104r$Select ALL true statements about Azure Backup for VMs.$az104r$, $az104r$[{"id":"a","text":"Backups are stored in a Recovery Services vault outside the VM's storage account."},{"id":"b","text":"Application-consistent backup uses VSS (Windows) or pre/post scripts (Linux)."},{"id":"c","text":"You can restore a VM-level recovery point, individual disks, or individual files."},{"id":"d","text":"A backup policy can be defined separately for each VM but not shared across many VMs."}]$az104r$::jsonb, $az104r$["a","b","c"]$az104r$::jsonb, $az104r$Backups live in the vault; consistency uses VSS or scripts; restores can be at VM, disk, or file level. A single policy can be assigned to many VMs (the same policy is shared, not per-VM only).$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/backup/backup-azure-vms-introduction","label":"Microsoft Learn — Azure VM backup overview"},{"url":"https://learn.microsoft.com/en-us/azure/backup/backup-azure-recovery-services-vault-overview","label":"Microsoft Learn — Recovery Services vault overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Select ALL true statements about Azure Backup for VMs.$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Monitor and maintain Azure resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A team needs to track which engineer modified a VM's NSG and when. Which log source is the system of record?$az104r$, $az104r$[{"id":"a","text":"Activity log for the subscription/resource group"},{"id":"b","text":"NSG flow logs only"},{"id":"c","text":"Boot diagnostics"},{"id":"d","text":"Service Health"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$The Activity log records all control-plane operations including NSG rule changes, with caller identity and timestamp. Flow logs record packet metadata, not change events; boot diagnostics show OS console; Service Health shows platform events.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/essentials/diagnostic-settings","label":"Microsoft Learn — Diagnostic settings in Azure Monitor"},{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/overview","label":"Microsoft Learn — Azure Monitor overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A team needs to track which engineer modified a VM's NSG and when. Which log source is the system of record?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Monitor and maintain Azure resources$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You want alerts to call an Azure Function for custom remediation when CPU > 90% for 10 minutes. Which Azure Monitor concept routes the alert to the function?$az104r$, $az104r$[{"id":"a","text":"An action group that includes a webhook or Function action"},{"id":"b","text":"A Recovery Services vault policy"},{"id":"c","text":"A diagnostic setting to storage"},{"id":"d","text":"An RBAC role assignment to the function"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Action groups define notification/automation actions (email, SMS, webhook, Function, Logic App, ITSM) fired by alert rules. The other options are unrelated to alert routing.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/alerts/action-groups","label":"Microsoft Learn — Action groups"},{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/alerts/alerts-overview","label":"Microsoft Learn — Overview of Azure Monitor alerts"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want alerts to call an Azure Function for custom remediation when CPU > 90% for 10 minutes. Which Azure Monitor concept routes the alert to the function?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Monitor and maintain Azure resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure Network Watcher feature continuously measures reachability and latency between two endpoints (e.g., a VM in spoke-vnet and a VM in hub-vnet)?$az104r$, $az104r$[{"id":"a","text":"Connection Monitor"},{"id":"b","text":"IP flow verify"},{"id":"c","text":"NSG diagnostic logs"},{"id":"d","text":"Effective Routes"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Connection Monitor runs ongoing reachability and latency tests between specified endpoints with alerting. IP flow verify is a one-shot check. NSG diagnostic logs and effective routes are configuration views.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/network-watcher/network-watcher-overview","label":"Microsoft Learn — What is Azure Network Watcher?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p2$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure Network Watcher feature continuously measures reachability and latency between two endpoints (e.g., a VM in spoke-vnet and a VM in hub-vnet)?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You want to invite an external accountant to access reports in your tenant once a month. Which identity model is most appropriate?$az104r$, $az104r$[{"id":"a","text":"Create a full member account in your tenant for the accountant"},{"id":"b","text":"Invite the accountant as a B2B guest using their existing email identity"},{"id":"c","text":"Share the global administrator credentials"},{"id":"d","text":"Disable Conditional Access temporarily"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$B2B guest invitations allow external users to authenticate with their existing identity and be granted scoped access. Full member accounts are heavier than needed; sharing admin credentials is forbidden; disabling CA is a security regression.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/entra/external-id/what-is-b2b","label":"Microsoft Learn — B2B collaboration overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want to invite an external accountant to access reports in your tenant once a month. Which identity model is most appropriate?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which built-in RBAC role is intended for users who need to manage all aspects of virtual networks but should NOT manage role assignments or access?$az104r$, $az104r$[{"id":"a","text":"Network Contributor"},{"id":"b","text":"Owner"},{"id":"c","text":"User Access Administrator"},{"id":"d","text":"Storage Account Contributor"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Network Contributor can manage networking resources but cannot assign roles. Owner can do everything including role assignment. User Access Administrator manages access. Storage Account Contributor manages storage accounts only.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/role-based-access-control/built-in-roles","label":"Microsoft Learn — Azure built-in roles"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which built-in RBAC role is intended for users who need to manage all aspects of virtual networks but should NOT manage role assignments or access?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You assign a Policy initiative at a management group with parameters specifying allowed VM SKUs. New subscriptions are added under the management group. What happens?$az104r$, $az104r$[{"id":"a","text":"New subscriptions inherit the assignment automatically; non-compliant deployments are denied."},{"id":"b","text":"You must reassign the initiative on every new subscription."},{"id":"c","text":"The initiative converts to advisory only."},{"id":"d","text":"Existing compliant resources become non-compliant."}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Management group-scoped policy assignments are inherited by all current and future child subscriptions and resource groups. There is nothing to redo per subscription. Compliance state of existing resources is independent of new assignments.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/governance/management-groups/overview","label":"Microsoft Learn — Organize your resources with management groups"},{"url":"https://learn.microsoft.com/en-us/azure/governance/policy/overview","label":"Microsoft Learn — What is Azure Policy?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You assign a Policy initiative at a management group with parameters specifying allowed VM SKUs. New subscriptions are added under the management group. What happens?$az104r$);
