INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$MULTI$az104r$::"QType", $az104r$Select ALL ways to define an Azure custom RBAC role.$az104r$, $az104r$[{"id":"a","text":"Azure portal Roles + administrators UI"},{"id":"b","text":"PowerShell (New-AzRoleDefinition with JSON)"},{"id":"c","text":"Azure CLI (az role definition create --role)"},{"id":"d","text":"Microsoft 365 admin center only"}]$az104r$::jsonb, $az104r$["a","b","c"]$az104r$::jsonb, $az104r$Custom roles can be authored in the portal, via PowerShell, or via the CLI. M365 admin center manages M365 roles, not Azure RBAC.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/role-based-access-control/custom-roles","label":"Microsoft Learn — Azure custom roles"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Select ALL ways to define an Azure custom RBAC role.$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A finance team wants a chargeback report broken down by department. Which Azure tagging strategy enables this?$az104r$, $az104r$[{"id":"a","text":"Apply a department tag on every resource and group cost views by that tag in Cost Management"},{"id":"b","text":"Use Resource locks for billing isolation"},{"id":"c","text":"Use NSGs to separate finance traffic"},{"id":"d","text":"Move resources to different regions for billing"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Cost Management can filter and group costs by tag, which is the standard chargeback pattern. Locks and NSGs are unrelated to billing; region does not equal department.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-resource-manager/management/tag-resources","label":"Microsoft Learn — Use tags to organize your Azure resources"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A finance team wants a chargeback report broken down by department. Which Azure tagging strategy enables this?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$Conditional Access "Block legacy authentication" affects which protocols?$az104r$, $az104r$[{"id":"a","text":"Modern authentication (OAuth) for browser sign-ins"},{"id":"b","text":"Basic authentication protocols like POP, IMAP, SMTP, and older Exchange Web Services without modern auth"},{"id":"c","text":"Microsoft Authenticator MFA"},{"id":"d","text":"FIDO2 security keys"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Legacy auth refers to protocols that don't support modern auth (e.g., POP/IMAP, older SMTP, older EWS). Blocking them removes a major attack surface for password spraying. Modern OAuth, MFA and FIDO2 are unaffected.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"},{"url":"https://learn.microsoft.com/en-us/entra/fundamentals/whatis","label":"Microsoft Learn — What is Microsoft Entra ID?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Conditional Access "Block legacy authentication" affects which protocols?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure Policy effect blocks a non-compliant request from being submitted to Azure Resource Manager?$az104r$, $az104r$[{"id":"a","text":"audit"},{"id":"b","text":"deny"},{"id":"c","text":"disabled"},{"id":"d","text":"append"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Deny evaluates the request and blocks it before it reaches the resource provider. Audit only logs non-compliance. Disabled turns the policy off. Append adds fields/tags but does not block.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/governance/policy/concepts/effect-basics","label":"Microsoft Learn — Understand Azure Policy effects"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure Policy effect blocks a non-compliant request from being submitted to Azure Resource Manager?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You want to assign a single Reader role at the root management group so all 50 subscriptions inherit read access for an auditor. Which prerequisite is required?$az104r$, $az104r$[{"id":"a","text":"You must elevate access to manage Azure resources at the root management group (one-time elevation as Global Administrator)"},{"id":"b","text":"A Conditional Access policy granting Reader"},{"id":"c","text":"A SAS token for the auditor"},{"id":"d","text":"A Recovery Services vault"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$A Global Administrator must first elevate access ("Access management for Azure resources" toggle) to gain User Access Administrator at the root scope. From there, role assignments can be made at the root management group.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/governance/management-groups/overview","label":"Microsoft Learn — Organize your resources with management groups"},{"url":"https://learn.microsoft.com/en-us/azure/role-based-access-control/overview","label":"Microsoft Learn — What is Azure RBAC?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want to assign a single Reader role at the root management group so all 50 subscriptions inherit read access for an auditor. Which prerequisite is required?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$Which Microsoft Entra ID feature is required for sign-in risk-based Conditional Access policies?$az104r$, $az104r$[{"id":"a","text":"Microsoft Entra ID P2"},{"id":"b","text":"Free tier"},{"id":"c","text":"Azure AD B2C standard tier only"},{"id":"d","text":"No license needed"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Risk-based policies (Identity Protection signals) require Microsoft Entra ID P2. P1 supports Conditional Access without risk; Free does not. B2C is a separate product for consumer identities.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/entra/identity/conditional-access/overview","label":"Microsoft Learn — Conditional Access overview"},{"url":"https://learn.microsoft.com/en-us/entra/fundamentals/whatis","label":"Microsoft Learn — What is Microsoft Entra ID?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Microsoft Entra ID feature is required for sign-in risk-based Conditional Access policies?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A team must be denied access to a specific virtual machine even though they have Contributor on the resource group. Which mechanism supports this?$az104r$, $az104r$[{"id":"a","text":"Resource lock"},{"id":"b","text":"Deny assignment (typically created by Azure-managed services like managed apps or Blueprints) or use Azure Policy deny"},{"id":"c","text":"NSG inbound deny rule"},{"id":"d","text":"Tag policy"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Deny assignments explicitly block specific actions on a resource and override allow assignments. They are typically created by managed services. Policy deny can also stop new deployments matching certain criteria. NSGs do network filtering, not RBAC.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/role-based-access-control/overview","label":"Microsoft Learn — What is Azure RBAC?"},{"url":"https://learn.microsoft.com/en-us/azure/governance/policy/concepts/effect-basics","label":"Microsoft Learn — Understand Azure Policy effects"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A team must be denied access to a specific virtual machine even though they have Contributor on the resource group. Which mechanism supports this?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$TRUE_FALSE$az104r$::"QType", $az104r$True or False: A management group in Azure can be nested up to six levels of depth below the root management group.$az104r$, $az104r$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":"Only 2 levels"},{"id":"d","text":"Only 4 levels"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$True. Microsoft documents a maximum of six levels of management group depth (excluding the root and subscription level).$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/governance/management-groups/overview","label":"Microsoft Learn — Organize your resources with management groups"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$True or False: A management group in Azure can be nested up to six levels of depth below the root management group.$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You enforce a policy that requires "secure transfer" (HTTPS) on all storage accounts. The audit shows several existing accounts non-compliant. What is the safest way to remediate at scale?$az104r$, $az104r$[{"id":"a","text":"Manually toggle each account"},{"id":"b","text":"Create a remediation task (deployIfNotExists or modify effect) that uses a managed identity with proper scope to fix non-compliant accounts"},{"id":"c","text":"Delete all non-compliant accounts"},{"id":"d","text":"Set the subscription to read-only"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Remediation tasks invoke the policy's deployIfNotExists/modify template using a managed identity, fixing existing non-compliant resources at scale safely and auditably. Manual fixes don't scale; deletion is destructive.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/governance/policy/concepts/effect-basics","label":"Microsoft Learn — Understand Azure Policy effects"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You enforce a policy that requires "secure transfer" (HTTPS) on all storage accounts. The audit shows several existing accounts non-compliant. What is the safest way to remediate at scale?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Manage Azure identities and governance$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You can grant a user permissions to a subset of users (e.g., only those in their department) in Microsoft Entra ID using which feature?$az104r$, $az104r$[{"id":"a","text":"Administrative units"},{"id":"b","text":"Resource groups"},{"id":"c","text":"Network Security Groups"},{"id":"d","text":"Recovery Services vault"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Administrative Units let you scope Entra ID admin roles to a subset of users, groups, or devices — useful for delegated administration in large tenants. RGs are for Azure resources, NSGs are network, RSV is for backups.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/entra/fundamentals/whatis","label":"Microsoft Learn — What is Microsoft Entra ID?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You can grant a user permissions to a subset of users (e.g., only those in their department) in Microsoft Entra ID using which feature?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You want to set up an immutable, WORM-style policy on a blob container so audit logs cannot be modified or deleted before a retention date. Which feature is purpose-built?$az104r$, $az104r$[{"id":"a","text":"Immutable storage policies (time-based retention or legal hold)"},{"id":"b","text":"Soft delete only"},{"id":"c","text":"Lifecycle management Archive transition"},{"id":"d","text":"Storage account read-only key"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Immutable storage for Blob applies time-based retention or legal hold to ensure WORM (write-once, read-many) compliance. Soft delete recovers items; lifecycle changes tiers; key state does not enforce immutability.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/blobs/storage-blobs-introduction","label":"Microsoft Learn — Introduction to Azure Blob Storage"},{"url":"https://learn.microsoft.com/en-us/azure/storage/blobs/soft-delete-blob-overview","label":"Microsoft Learn — Soft delete for blobs"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want to set up an immutable, WORM-style policy on a blob container so audit logs cannot be modified or deleted before a retention date. Which feature is purpose-built?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You configure object replication on a source storage account to a destination account in another region. What is replicated?$az104r$, $az104r$[{"id":"a","text":"All blob types including page and append blobs"},{"id":"b","text":"Block blobs only (with versioning and change feed enabled on source)"},{"id":"c","text":"Queues and tables"},{"id":"d","text":"File shares"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Object replication copies block blobs asynchronously between accounts, with versioning + change feed required on source. Page/append blobs, queues, tables, and file shares are not replicated by this feature.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/blobs/storage-blobs-introduction","label":"Microsoft Learn — Introduction to Azure Blob Storage"},{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-account-overview","label":"Microsoft Learn — Storage account overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You configure object replication on a source storage account to a destination account in another region. What is replicated?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure Storage redundancy option keeps three copies in a single datacenter and is the cheapest, with the lowest durability?$az104r$, $az104r$[{"id":"a","text":"LRS"},{"id":"b","text":"ZRS"},{"id":"c","text":"GRS"},{"id":"d","text":"GZRS"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$LRS replicates three copies in one datacenter. ZRS spreads across zones; GRS adds an async secondary region; GZRS combines both. LRS is the cheapest and least durable.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-redundancy","label":"Microsoft Learn — Azure Storage redundancy"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure Storage redundancy option keeps three copies in a single datacenter and is the cheapest, with the lowest durability?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$A SAS issued from a user-delegation key uses what to sign requests instead of a storage account key?$az104r$, $az104r$[{"id":"a","text":"The storage account access key"},{"id":"b","text":"A Microsoft Entra ID-based user delegation key obtained from the storage service"},{"id":"c","text":"A static certificate stored in Key Vault"},{"id":"d","text":"No signing is required"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$A user-delegation SAS is signed with a user-delegation key obtained from the storage service after the user authenticates with Entra ID. This avoids exposing the account key.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-sas-overview","label":"Microsoft Learn — Grant limited access with shared access signatures"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A SAS issued from a user-delegation key uses what to sign requests instead of a storage account key?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which storage feature exposes blob data to Azure Data Lake Storage Gen2 APIs (hierarchical namespace, ACLs, POSIX-like operations)?$az104r$, $az104r$[{"id":"a","text":"Enable hierarchical namespace on the storage account at creation"},{"id":"b","text":"Use Azure Files SMB"},{"id":"c","text":"Mount the blob as a managed disk"},{"id":"d","text":"Use Cosmos DB instead"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Hierarchical namespace (HNS), enabled at account creation, turns a storage account into Azure Data Lake Storage Gen2 with directory semantics and POSIX-like ACLs. Files SMB, disks, and Cosmos are different services.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-account-overview","label":"Microsoft Learn — Storage account overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which storage feature exposes blob data to Azure Data Lake Storage Gen2 APIs (hierarchical namespace, ACLs, POSIX-like operations)?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A storage account has a private endpoint and the firewall set to "Selected networks" with no VNets. Public clients fail to read blobs. What is required to allow on-prem clients via VPN to read blobs?$az104r$, $az104r$[{"id":"a","text":"Route the on-prem subnet to the VNet (S2S VPN/ExpressRoute) and ensure DNS resolves the privatelink alias to the private IP"},{"id":"b","text":"Re-enable public access"},{"id":"c","text":"Set the storage account to LRS"},{"id":"d","text":"Use Storage Explorer with account keys only"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Private endpoints are reachable from networks routed to the VNet (e.g., on-prem via VPN/ExpressRoute) provided DNS resolves the privatelink alias to the private IP. Disabling private access defeats the purpose.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-private-endpoints","label":"Microsoft Learn — Use private endpoints for Azure Storage"},{"url":"https://learn.microsoft.com/en-us/azure/dns/private-dns-overview","label":"Microsoft Learn — What is Azure Private DNS?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A storage account has a private endpoint and the firewall set to "Selected networks" with no VNets. Public clients fail to read blobs. What is required to allow on-prem clients via VPN to read blobs?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$MULTI$az104r$::"QType", $az104r$Select ALL true statements about Azure Files share snapshots.$az104r$, $az104r$[{"id":"a","text":"Snapshots are read-only point-in-time copies of the share."},{"id":"b","text":"Snapshots can be taken manually or by Azure Backup policies."},{"id":"c","text":"Snapshots replace daily backups for compliance retention beyond 30 days."},{"id":"d","text":"Restoring from a snapshot can be done by copy or by promoting the snapshot to the share."}]$az104r$::jsonb, $az104r$["a","b","d"]$az104r$::jsonb, $az104r$Snapshots are read-only, can be manual or backup-scheduled, and support file/path restores. They are good for short-term restore but Azure Backup with Recovery Services vault is the recommended long-retention backup mechanism.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/files/storage-files-introduction","label":"Microsoft Learn — What is Azure Files?"},{"url":"https://learn.microsoft.com/en-us/azure/backup/backup-overview","label":"Microsoft Learn — Overview of Azure Backup"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Select ALL true statements about Azure Files share snapshots.$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$A blob storage account uses customer-managed keys (CMK) for encryption. The key in Key Vault is accidentally disabled. What happens to blob reads?$az104r$, $az104r$[{"id":"a","text":"Reads succeed using a cached key for a few hours."},{"id":"b","text":"Reads start failing because the storage service cannot wrap/unwrap data using the disabled key."},{"id":"c","text":"Blobs auto-decrypt with the default platform key."},{"id":"d","text":"Nothing — only writes fail."}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$When the CMK is disabled or revoked, the storage service cannot access the key encryption key, so both reads and writes that require key access begin to fail. This is by design for revocation semantics.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-account-overview","label":"Microsoft Learn — Storage account overview"},{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-account-keys-manage","label":"Microsoft Learn — Manage storage account access keys"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A blob storage account uses customer-managed keys (CMK) for encryption. The key in Key Vault is accidentally disabled. What happens to blob reads?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which command-line tool offers a parallelized sync mode similar to rsync between a local directory and a blob container?$az104r$, $az104r$[{"id":"a","text":"azcopy sync"},{"id":"b","text":"Robocopy /MIR"},{"id":"c","text":"rsync --azure"},{"id":"d","text":"Storage Explorer sync wizard"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$`azcopy sync` mirrors a local directory with a blob container, copying only changes. Robocopy is Windows-local, rsync has no native Azure backend, and Storage Explorer does not have a CLI sync command.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-use-azcopy-v10","label":"Microsoft Learn — Get started with AzCopy"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which command-line tool offers a parallelized sync mode similar to rsync between a local directory and a blob container?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You want infrequently accessed data older than 90 days moved to Cool tier and then to Archive after 365 days. Which feature automates this?$az104r$, $az104r$[{"id":"a","text":"Lifecycle management rules on the storage account"},{"id":"b","text":"A daily PowerShell script"},{"id":"c","text":"Azure Backup retention policy"},{"id":"d","text":"Storage account replication"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Lifecycle management rules use age-based filters to transition blobs between tiers (Cool, Cold, Archive) automatically. A custom script is unnecessary; Backup retention and replication are unrelated.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/blobs/lifecycle-management-overview","label":"Microsoft Learn — Optimize costs with lifecycle management"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want infrequently accessed data older than 90 days moved to Cool tier and then to Archive after 365 days. Which feature automates this?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$Your application reads many small files from an Azure Files share and complains about latency. Which change yields the largest improvement?$az104r$, $az104r$[{"id":"a","text":"Switch the share from Standard (HDD) to Premium (SSD) FileStorage account"},{"id":"b","text":"Add more storage account access keys"},{"id":"c","text":"Enable geo-redundant storage (GRS)"},{"id":"d","text":"Increase the storage account access tier"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Premium Azure Files (SSD) drastically reduces latency for small-file workloads. Adding keys, enabling GRS, or changing tiers does not improve file-share latency.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/files/storage-files-introduction","label":"Microsoft Learn — What is Azure Files?"},{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-account-overview#types-of-storage-accounts","label":"Microsoft Learn — Types of storage accounts"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Your application reads many small files from an Azure Files share and complains about latency. Which change yields the largest improvement?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage storage$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which storage account property controls whether you can authorize requests using Microsoft Entra ID (in addition to or instead of account keys)?$az104r$, $az104r$[{"id":"a","text":"Default to Entra authorization (in the Configuration blade) and assign appropriate data-plane RBAC roles like \"Storage Blob Data Contributor\""},{"id":"b","text":"Disable HTTPS"},{"id":"c","text":"Set redundancy to GRS"},{"id":"d","text":"Enable static website hosting"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Entra ID-based data-plane access uses RBAC roles on the storage account or container; you can also set "default to Entra" in Configuration to prefer it in the portal. HTTPS, GRS and static websites are unrelated to authorization.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/storage/common/storage-account-overview","label":"Microsoft Learn — Storage account overview"},{"url":"https://learn.microsoft.com/en-us/azure/role-based-access-control/overview","label":"Microsoft Learn — What is Azure RBAC?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which storage account property controls whether you can authorize requests using Microsoft Entra ID (in addition to or instead of account keys)?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure compute service runs short, event-driven code without provisioning servers and bills per execution?$az104r$, $az104r$[{"id":"a","text":"Azure Virtual Machines"},{"id":"b","text":"Azure Functions (Consumption plan)"},{"id":"c","text":"Azure Kubernetes Service"},{"id":"d","text":"Azure Container Registry"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Azure Functions Consumption plan is the serverless execution model with per-execution billing. VMs are always running, AKS hosts clusters, ACR stores images.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/app-service/overview","label":"Microsoft Learn — Azure App Service overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure compute service runs short, event-driven code without provisioning servers and bills per execution?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure VM feature ensures Microsoft will not co-locate your VMs with another customer's VMs on the same physical host?$az104r$, $az104r$[{"id":"a","text":"Azure Dedicated Host"},{"id":"b","text":"Availability set"},{"id":"c","text":"VM Scale Set"},{"id":"d","text":"Standard SSD"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Azure Dedicated Host gives you a single-tenant physical server for your VMs, useful for compliance or licensing. Availability sets and scale sets are about availability/scale, not tenancy. Disk SKU is unrelated.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/overview","label":"Microsoft Learn — Virtual machines in Azure"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/sizes","label":"Microsoft Learn — Sizes for virtual machines in Azure"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure VM feature ensures Microsoft will not co-locate your VMs with another customer's VMs on the same physical host?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$In an App Service plan, slot swaps fail to keep environment-specific app settings tied to the slot. Which feature solves this?$az104r$, $az104r$[{"id":"a","text":"Mark specific app settings and connection strings as \"slot setting\" (deployment slot setting) so they remain with the slot during swap"},{"id":"b","text":"Use Storage queues to pass settings"},{"id":"c","text":"Always restart after swap"},{"id":"d","text":"Disable Continuous Deployment"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Marking a setting as a "deployment slot setting" pins it to the slot during swap, so production-only secrets stay in production after a swap. Restarts and CD toggles do not solve this.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/app-service/overview","label":"Microsoft Learn — Azure App Service overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$In an App Service plan, slot swaps fail to keep environment-specific app settings tied to the slot. Which feature solves this?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 3, $az104r$MULTI$az104r$::"QType", $az104r$Select ALL true statements about Azure VM scale sets in Flexible orchestration mode.$az104r$, $az104r$[{"id":"a","text":"Each VM is created as a standard VM and gets its own resource ID."},{"id":"b","text":"Flexible mode supports fault domains and zones for high availability."},{"id":"c","text":"Flexible mode is the recommended orchestration mode for most new scale sets."},{"id":"d","text":"Flexible mode cannot use VM extensions."}]$az104r$::jsonb, $az104r$["a","b","c"]$az104r$::jsonb, $az104r$Flexible orchestration treats VMs as standard resources, supports FDs/zones, and is the recommended default. VM extensions work in flexible mode. Uniform mode still exists but is legacy for many scenarios.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-machine-scale-sets/overview","label":"Microsoft Learn — Virtual Machine Scale Sets overview"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/overview","label":"Microsoft Learn — Virtual machines in Azure"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Select ALL true statements about Azure VM scale sets in Flexible orchestration mode.$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You want to redeploy a VM whose OS disk became corrupted, preserving the original IP and NIC. Which option in the portal is correct?$az104r$, $az104r$[{"id":"a","text":"Redeploy (which moves the VM to a new host and reboots)"},{"id":"b","text":"Stop deallocate then change region"},{"id":"c","text":"Delete and recreate the entire VM"},{"id":"d","text":"Convert to Spot"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Redeploy moves the VM to a new Azure host while keeping its disks, NIC, and IP, often resolving host-side issues. The other options are too disruptive or unrelated.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/overview","label":"Microsoft Learn — Virtual machines in Azure"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want to redeploy a VM whose OS disk became corrupted, preserving the original IP and NIC. Which option in the portal is correct?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure storage option for a VM is required to use Azure Site Recovery replication?$az104r$, $az104r$[{"id":"a","text":"Managed disks (or unmanaged supported via legacy)"},{"id":"b","text":"Cool tier blobs only"},{"id":"c","text":"Premium files only"},{"id":"d","text":"Archive tier blobs"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$ASR replicates VMs using managed disks (recommended); some legacy unmanaged configurations exist but are deprecated. Cool tier blobs, premium files, and archive tier are not VM disk types.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/site-recovery/site-recovery-overview","label":"Microsoft Learn — About Azure Site Recovery"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/managed-disks-overview","label":"Microsoft Learn — Azure managed disks overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure storage option for a VM is required to use Azure Site Recovery replication?$az104r$);
