INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A new VM template uses a Bicep parameter for adminPassword. Which option avoids storing the password in source control?$az104r$, $az104r$[{"id":"a","text":"Use a Key Vault reference (parameters file references a secret URI) so the value is fetched at deploy time"},{"id":"b","text":"Hardcode it in the Bicep file"},{"id":"c","text":"Email the password between team members"},{"id":"d","text":"Disable the password requirement"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Key Vault references in parameter files let ARM/Bicep deployments fetch secrets at deployment time without checking them into source. Hardcoding/emailing secrets is insecure; disabling auth is not acceptable.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-resource-manager/bicep/overview","label":"Microsoft Learn — What is Bicep?"},{"url":"https://learn.microsoft.com/en-us/azure/azure-resource-manager/templates/overview","label":"Microsoft Learn — ARM template overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A new VM template uses a Bicep parameter for adminPassword. Which option avoids storing the password in source control?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A team wants to scale containers based on RabbitMQ queue length. Which Azure container service has first-class KEDA support?$az104r$, $az104r$[{"id":"a","text":"Azure Container Apps"},{"id":"b","text":"Azure Container Instances"},{"id":"c","text":"Azure App Service free tier"},{"id":"d","text":"Azure Functions Dedicated plan"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Azure Container Apps embeds KEDA for event-driven scale rules (queues, HTTP, custom). ACI is a single container without KEDA. App Service free and Functions Dedicated plans are unrelated.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/aks/what-is-aks","label":"Microsoft Learn — Azure Kubernetes Service overview"},{"url":"https://learn.microsoft.com/en-us/azure/app-service/overview","label":"Microsoft Learn — Azure App Service overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A team wants to scale containers based on RabbitMQ queue length. Which Azure container service has first-class KEDA support?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You can't pull an image from ACR to your AKS cluster. Which authorization is typically missing for the cluster's kubelet identity?$az104r$, $az104r$[{"id":"a","text":"AcrPull role on the registry, granted to the cluster's kubelet managed identity (or use az aks update --attach-acr)"},{"id":"b","text":"Owner role on the subscription"},{"id":"c","text":"Storage Blob Data Reader on the AKS cluster"},{"id":"d","text":"Reader on Resource Manager only"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$AKS uses its kubelet managed identity (or service principal) to pull images; that identity must hold AcrPull on the ACR. `az aks update --attach-acr` automates the role assignment.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/aks/what-is-aks","label":"Microsoft Learn — Azure Kubernetes Service overview"},{"url":"https://learn.microsoft.com/en-us/azure/container-registry/container-registry-intro","label":"Microsoft Learn — Azure Container Registry introduction"},{"url":"https://learn.microsoft.com/en-us/azure/role-based-access-control/overview","label":"Microsoft Learn — What is Azure RBAC?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You can't pull an image from ACR to your AKS cluster. Which authorization is typically missing for the cluster's kubelet identity?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure feature lets you reuse Windows Server and SQL Server licenses with Software Assurance on Azure VMs to reduce cost?$az104r$, $az104r$[{"id":"a","text":"Azure Hybrid Benefit"},{"id":"b","text":"Spot pricing"},{"id":"c","text":"Reserved capacity for blobs"},{"id":"d","text":"Dev/Test offer for storage accounts only"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Azure Hybrid Benefit applies on-prem Windows/SQL licenses with SA to reduce Azure compute cost. Spot, reserved blob capacity, and Dev/Test storage offers do not provide license discounts.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/overview","label":"Microsoft Learn — Virtual machines in Azure"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure feature lets you reuse Windows Server and SQL Server licenses with Software Assurance on Azure VMs to reduce cost?$az104r$);
