INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Deploy and manage Azure compute resources$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$A workload spreads VMs across two Availability Zones in the same region. The region experiences a single-zone power event. What is expected?$az104r$, $az104r$[{"id":"a","text":"Both zones are affected; the workload fails entirely."},{"id":"b","text":"Only the affected zone's VMs are impacted; VMs in the other zone continue to serve traffic."},{"id":"c","text":"Microsoft automatically restores all VMs across the public internet."},{"id":"d","text":"The VMs are migrated to another region."}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Availability Zones provide physical isolation (power, cooling, network). A single-zone failure should not affect VMs in other zones in the region. Cross-region failover requires ASR.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/reliability/availability-zones-overview","label":"Microsoft Learn — Availability zones"},{"url":"https://learn.microsoft.com/en-us/azure/site-recovery/site-recovery-overview","label":"Microsoft Learn — About Azure Site Recovery"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A workload spreads VMs across two Availability Zones in the same region. The region experiences a single-zone power event. What is expected?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which load balancing service is best for DNS-based routing across globally distributed regions (e.g., direct users to the closest healthy region)?$az104r$, $az104r$[{"id":"a","text":"Traffic Manager"},{"id":"b","text":"Internal Load Balancer"},{"id":"c","text":"Application Gateway"},{"id":"d","text":"NAT Gateway"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Traffic Manager is a DNS-based load balancer with routing methods (Performance, Geographic, Priority, Weighted). Internal LB is regional L4. App Gateway is regional L7. NAT Gateway is outbound SNAT.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/load-balancer/load-balancer-overview","label":"Microsoft Learn — What is Azure Load Balancer?"},{"url":"https://learn.microsoft.com/en-us/azure/frontdoor/front-door-overview","label":"Microsoft Learn — What is Azure Front Door?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which load balancing service is best for DNS-based routing across globally distributed regions (e.g., direct users to the closest healthy region)?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You want a single global IP that load balances HTTPS to backends in three regions with edge TLS termination and acceleration. Which service?$az104r$, $az104r$[{"id":"a","text":"Azure Front Door"},{"id":"b","text":"Traffic Manager"},{"id":"c","text":"Cross-region Standard Load Balancer (regional only)"},{"id":"d","text":"Azure Bastion"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Front Door is the global L7 service with a single anycast IP, edge TLS, WAF, and intelligent routing. Traffic Manager is DNS-only. LB is regional. Bastion is for RDP/SSH.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/frontdoor/front-door-overview","label":"Microsoft Learn — What is Azure Front Door?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want a single global IP that load balances HTTPS to backends in three regions with edge TLS termination and acceleration. Which service?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$Two VMs in the same subnet cannot ping each other. NSG rules show ICMP Inbound denied by default. Which two changes will allow ICMP between them?$az104r$, $az104r$[{"id":"a","text":"Add an NSG rule allowing ICMP from VirtualNetwork to VirtualNetwork at high priority"},{"id":"b","text":"Disable Windows Firewall on both VMs if Windows; ensure no NSG denies ICMP between them (default rule \"AllowVnetInBound\" should allow it)"},{"id":"c","text":"Change region"},{"id":"d","text":"Convert the subnet to /29"}]$az104r$::jsonb, $az104r$["b"]$az104r$::jsonb, $az104r$Default NSG rules allow VirtualNetwork-to-VirtualNetwork traffic. ICMP failures within a subnet are typically guest OS firewalls (Windows Firewall blocks ICMP by default). Region/CIDR are not relevant.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/network-security-groups-overview","label":"Microsoft Learn — Network security groups"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/virtual-networks-overview","label":"Microsoft Learn — What is Azure Virtual Network?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Two VMs in the same subnet cannot ping each other. NSG rules show ICMP Inbound denied by default. Which two changes will allow ICMP between them?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure service provides DNS resolution that conditionally forwards to on-prem DNS servers from within an Azure VNet?$az104r$, $az104r$[{"id":"a","text":"Azure DNS Private Resolver with outbound endpoints"},{"id":"b","text":"Azure Public DNS only"},{"id":"c","text":"Custom DNS on every VM"},{"id":"d","text":"Service tags"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Azure DNS Private Resolver provides inbound/outbound endpoints and conditional forwarders to bridge on-prem and Azure DNS without managing custom DNS VMs. Public DNS doesn't do conditional forwarding; per-VM DNS doesn't scale.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/dns/dns-overview","label":"Microsoft Learn — What is Azure DNS?"},{"url":"https://learn.microsoft.com/en-us/azure/dns/private-dns-overview","label":"Microsoft Learn — What is Azure Private DNS?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure service provides DNS resolution that conditionally forwards to on-prem DNS servers from within an Azure VNet?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A NSG rule allows TCP 443 from a specific public IP range to a VM, but traffic is dropped. Which Network Watcher tool helps verify which rule matched and the effective rules applied?$az104r$, $az104r$[{"id":"a","text":"IP flow verify and Effective security rules on the NIC"},{"id":"b","text":"Connection Monitor only"},{"id":"c","text":"Activity log"},{"id":"d","text":"NSG flow logs only"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$IP flow verify simulates a packet and tells you which NSG rule allowed/denied it. Effective security rules show the merged rule set applied to the NIC. Connection Monitor measures reachability over time; flow logs are bulk telemetry.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/network-watcher/network-watcher-overview","label":"Microsoft Learn — What is Azure Network Watcher?"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/network-security-groups-overview","label":"Microsoft Learn — Network security groups"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A NSG rule allows TCP 443 from a specific public IP range to a VM, but traffic is dropped. Which Network Watcher tool helps verify which rule matched and the effective rules applied?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure feature lets you deploy a regional next-generation firewall as a managed service with FQDN filtering and threat intelligence?$az104r$, $az104r$[{"id":"a","text":"Azure Firewall (Standard/Premium)"},{"id":"b","text":"NSG only"},{"id":"c","text":"Network Watcher"},{"id":"d","text":"NAT Gateway"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Azure Firewall is a stateful, managed next-gen firewall with FQDN filtering, threat intel, and TLS inspection (Premium). NSGs are 5-tuple filters; Network Watcher is diagnostics; NAT Gateway is for outbound SNAT only.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/virtual-networks-overview","label":"Microsoft Learn — What is Azure Virtual Network?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure feature lets you deploy a regional next-generation firewall as a managed service with FQDN filtering and threat intelligence?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$You want to ensure outbound traffic from a subnet uses a predictable public IP for partner allow-listing. Which approach is recommended?$az104r$, $az104r$[{"id":"a","text":"Associate a NAT Gateway with the subnet and attach static public IP(s)"},{"id":"b","text":"Assign a public IP to every VM"},{"id":"c","text":"Use default outbound access (random SNAT)"},{"id":"d","text":"Disable internet access entirely"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$NAT Gateway provides scalable, predictable outbound SNAT with the public IPs you assign. Per-VM public IPs do not scale and complicate firewall allow-lists. Default outbound access is being deprecated and uses random IPs.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/nat-gateway/nat-overview","label":"Microsoft Learn — What is Virtual Network NAT?"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/ip-services/public-ip-addresses","label":"Microsoft Learn — Public IP addresses"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You want to ensure outbound traffic from a subnet uses a predictable public IP for partner allow-listing. Which approach is recommended?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$MULTI$az104r$::"QType", $az104r$Select ALL true statements about Azure ExpressRoute.$az104r$, $az104r$[{"id":"a","text":"ExpressRoute connections do not traverse the public internet."},{"id":"b","text":"ExpressRoute supports private peering (to VNets) and Microsoft peering (to Microsoft 365/Azure PaaS services)."},{"id":"c","text":"ExpressRoute requires a connectivity provider or ExpressRoute Direct port."},{"id":"d","text":"ExpressRoute is encrypted end-to-end by default at L3."}]$az104r$::jsonb, $az104r$["a","b","c"]$az104r$::jsonb, $az104r$ExpressRoute is private (not public), supports private and Microsoft peering, and requires a provider or Direct port. It is NOT encrypted at L3 by default; customers can add IPSec over ExpressRoute if needed.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/expressroute/expressroute-introduction","label":"Microsoft Learn — What is Azure ExpressRoute?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Select ALL true statements about Azure ExpressRoute.$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You need a load balancer for internal apps inside a VNet (private frontend IP). Which Azure Load Balancer type fits?$az104r$, $az104r$[{"id":"a","text":"Internal Load Balancer (Standard)"},{"id":"b","text":"Public Load Balancer (Basic)"},{"id":"c","text":"Gateway Load Balancer"},{"id":"d","text":"Cross-region Load Balancer only"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Internal LB has a private frontend IP for VNet-local distribution. Public LB has a public frontend. Gateway LB is for NVA chaining. Cross-region is global.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/load-balancer/load-balancer-overview","label":"Microsoft Learn — What is Azure Load Balancer?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You need a load balancer for internal apps inside a VNet (private frontend IP). Which Azure Load Balancer type fits?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$A web app behind Front Door is hitting the origin too often. Which feature reduces backend load?$az104r$, $az104r$[{"id":"a","text":"Edge caching policies on Front Door"},{"id":"b","text":"NSG egress rate limits"},{"id":"c","text":"Application Gateway WAF Core Rule Set"},{"id":"d","text":"NAT Gateway capacity"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Front Door supports caching at the edge POPs for cacheable responses, reducing origin load. NSGs, App Gateway WAF, and NAT Gateway do not provide caching.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/frontdoor/front-door-overview","label":"Microsoft Learn — What is Azure Front Door?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A web app behind Front Door is hitting the origin too often. Which feature reduces backend load?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which feature lets you peer two VNets in different Microsoft Entra tenants?$az104r$, $az104r$[{"id":"a","text":"Cross-tenant VNet peering (configure with resource IDs and authorize via role assignments in both directions)"},{"id":"b","text":"Service endpoint sharing"},{"id":"c","text":"ExpressRoute Direct only"},{"id":"d","text":"Tenant-level NSG"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$VNet peering supports cross-tenant configurations using resource IDs and explicit role assignments in both tenants (e.g., Network Contributor). Service endpoints, ExpressRoute, and "tenant-level NSG" are not peering mechanisms.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/virtual-network-peering-overview","label":"Microsoft Learn — Virtual network peering"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which feature lets you peer two VNets in different Microsoft Entra tenants?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A web app at https://app.contoso.com behind App Gateway WAF must reject requests with SQL injection patterns. Which WAF mode should be used for protection rather than just logging?$az104r$, $az104r$[{"id":"a","text":"Prevention (Block) mode"},{"id":"b","text":"Detection (Log only) mode"},{"id":"c","text":"Off"},{"id":"d","text":"Audit-only"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Prevention mode blocks requests matching WAF rules. Detection mode only logs them. "Off" disables WAF, and "Audit-only" is not a separate WAF mode.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/application-gateway/overview","label":"Microsoft Learn — What is Azure Application Gateway?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A web app at https://app.contoso.com behind App Gateway WAF must reject requests with SQL injection patterns. Which WAF mode should be used for protection rather than just logging?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$Two on-prem sites need redundant connectivity to a single Azure VNet. Which configuration meets this?$az104r$, $az104r$[{"id":"a","text":"Two ExpressRoute circuits in different peering locations to the same VNet, with BGP for failover (or active/active VPN gateways with multiple S2S connections)"},{"id":"b","text":"A single ExpressRoute circuit only"},{"id":"c","text":"A single S2S VPN connection"},{"id":"d","text":"NSG with priority 65000"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Two ExpressRoute circuits (or active/active VPN with multiple S2S connections) using BGP provide redundancy. A single circuit/connection has no redundancy. NSG priorities do not provide WAN redundancy.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/expressroute/expressroute-introduction","label":"Microsoft Learn — What is Azure ExpressRoute?"},{"url":"https://learn.microsoft.com/en-us/azure/vpn-gateway/vpn-gateway-about-vpngateways","label":"Microsoft Learn — What is VPN Gateway?"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Two on-prem sites need redundant connectivity to a single Azure VNet. Which configuration meets this?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Implement and manage virtual networking$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You need a private, scalable outbound static IP set for a subnet of VMs that must reach a partner API allow-listed by source IP. Which Azure resource provides this with a deterministic SNAT pool?$az104r$, $az104r$[{"id":"a","text":"A NAT Gateway with one or more Standard SKU public IPs (or a public IP prefix) attached to the subnet"},{"id":"b","text":"Per-VM public IPs assigned dynamically"},{"id":"c","text":"Service endpoint to Microsoft.Storage"},{"id":"d","text":"Application Gateway frontend"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$NAT Gateway gives a subnet a deterministic SNAT pool from the attached Standard public IPs/prefix, so partners can allow-list those IPs. Per-VM dynamic IPs change; service endpoints only reach Microsoft PaaS; App Gateway is inbound L7.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/nat-gateway/nat-overview","label":"Microsoft Learn — What is Virtual Network NAT?"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-network/ip-services/public-ip-addresses","label":"Microsoft Learn — Public IP addresses"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You need a private, scalable outbound static IP set for a subnet of VMs that must reach a partner API allow-listed by source IP. Which Azure resource provides this with a deterministic SNAT pool?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Monitor and maintain Azure resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure Monitor metric alert signal type is best for "average CPU > 80% for 5 minutes" on multiple VMs at once?$az104r$, $az104r$[{"id":"a","text":"A metric alert with multi-resource scope and dynamic or static threshold"},{"id":"b","text":"A log alert query that re-runs every minute"},{"id":"c","text":"A Service Health alert"},{"id":"d","text":"An NSG flow log alert"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Metric alerts support multi-resource scope (multiple VMs in one rule) with static or dynamic thresholds and lower cost than log alerts. Log alerts work but cost more for simple metric-based scenarios. Service Health and flow logs are unrelated.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/alerts/alerts-overview","label":"Microsoft Learn — Overview of Azure Monitor alerts"},{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/essentials/data-platform-metrics","label":"Microsoft Learn — Azure Monitor Metrics overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure Monitor metric alert signal type is best for "average CPU > 80% for 5 minutes" on multiple VMs at once?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Monitor and maintain Azure resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You enable diagnostic settings on a storage account to send logs to a Log Analytics workspace. Which kind of logs can be sent?$az104r$, $az104r$[{"id":"a","text":"Resource logs (e.g., StorageRead, StorageWrite, StorageDelete) and metrics"},{"id":"b","text":"Only Activity log entries"},{"id":"c","text":"Only NSG flow logs"},{"id":"d","text":"Only Sign-in logs"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Diagnostic settings export per-resource diagnostic logs (resource logs) and platform metrics. Activity log is subscription-level; flow logs are NSG/Network Watcher; sign-in logs are Entra ID.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/essentials/diagnostic-settings","label":"Microsoft Learn — Diagnostic settings in Azure Monitor"},{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/logs/data-platform-logs","label":"Microsoft Learn — Azure Monitor Logs overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You enable diagnostic settings on a storage account to send logs to a Log Analytics workspace. Which kind of logs can be sent?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Monitor and maintain Azure resources$az104r$, 3, $az104r$MULTI$az104r$::"QType", $az104r$Select ALL true statements about Azure Monitor alerts.$az104r$, $az104r$[{"id":"a","text":"Alert rules consist of a target/scope, a signal/condition, and one or more action groups."},{"id":"b","text":"Alerts have severity levels Sev 0 (critical) through Sev 4 (verbose)."},{"id":"c","text":"A single alert rule can trigger multiple action groups simultaneously."},{"id":"d","text":"An alert can only send email and cannot call a webhook."}]$az104r$::jsonb, $az104r$["a","b","c"]$az104r$::jsonb, $az104r$Alerts are composed of scope + condition + action groups; severities range Sev 0-4; multiple action groups are allowed. Action groups support webhooks, Functions, Logic Apps, ITSM, voice, SMS, and email.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/alerts/alerts-overview","label":"Microsoft Learn — Overview of Azure Monitor alerts"},{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/alerts/action-groups","label":"Microsoft Learn — Action groups"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Select ALL true statements about Azure Monitor alerts.$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Monitor and maintain Azure resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$A storage account in westeurope has degraded performance reported in Azure Service Health. Where do affected customers see personalized impact in their resource view?$az104r$, $az104r$[{"id":"a","text":"Resource Health for the storage account"},{"id":"b","text":"NSG flow logs"},{"id":"c","text":"Activity log only"},{"id":"d","text":"App Insights live metrics"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Resource Health surfaces the personalized impact of platform issues on individual resources. Service Health is the platform-wide view; Activity log records change events; App Insights is for app telemetry.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/service-health/resource-health-overview","label":"Microsoft Learn — Resource Health overview"},{"url":"https://learn.microsoft.com/en-us/azure/service-health/overview","label":"Microsoft Learn — Azure Service Health overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A storage account in westeurope has degraded performance reported in Azure Service Health. Where do affected customers see personalized impact in their resource view?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Monitor and maintain Azure resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$Which Azure Backup option for VMs allows you to retain weekly recovery points beyond the daily retention horizon?$az104r$, $az104r$[{"id":"a","text":"A backup policy that includes weekly, monthly, and yearly retention rules"},{"id":"b","text":"Soft delete on the storage account"},{"id":"c","text":"NSG flow log retention"},{"id":"d","text":"Activity log diagnostic settings retention"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Azure Backup policies define daily/weekly/monthly/yearly retention windows for recovery points. Soft delete, flow log retention, and Activity log diagnostic retention are different concepts.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/backup/backup-azure-vms-introduction","label":"Microsoft Learn — Azure VM backup overview"},{"url":"https://learn.microsoft.com/en-us/azure/backup/backup-azure-recovery-services-vault-overview","label":"Microsoft Learn — Recovery Services vault overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$Which Azure Backup option for VMs allows you to retain weekly recovery points beyond the daily retention horizon?$az104r$);
