INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Monitor and maintain Azure resources$az104r$, 2, $az104r$SINGLE$az104r$::"QType", $az104r$You need to archive Activity log entries for 7 years for compliance. Which destination is appropriate?$az104r$, $az104r$[{"id":"a","text":"Diagnostic setting from the subscription Activity log to a storage account with retention or Log Analytics with long-term retention/archive"},{"id":"b","text":"A custom VM running ELK"},{"id":"c","text":"Microsoft Teams channel only"},{"id":"d","text":"Email distribution group"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Diagnostic settings can route Activity log to storage with multi-year retention or Log Analytics with archive tiering for cost-effective long-term retention. Self-hosted ELK, Teams, or email are not compliance-grade.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/essentials/diagnostic-settings","label":"Microsoft Learn — Diagnostic settings in Azure Monitor"},{"url":"https://learn.microsoft.com/en-us/azure/azure-monitor/overview","label":"Microsoft Learn — Azure Monitor overview"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$You need to archive Activity log entries for 7 years for compliance. Which destination is appropriate?$az104r$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $az104r$Monitor and maintain Azure resources$az104r$, 3, $az104r$SINGLE$az104r$::"QType", $az104r$A VM Backup repeatedly fails with an extension error. Which step is typically the first remediation?$az104r$, $az104r$[{"id":"a","text":"Reinstall or update the VMSnapshot/IaaSVMExtension on the VM"},{"id":"b","text":"Recreate the entire VM"},{"id":"c","text":"Move the VM to another region"},{"id":"d","text":"Switch the storage account to GRS"}]$az104r$::jsonb, $az104r$["a"]$az104r$::jsonb, $az104r$Backup uses an in-guest extension. Reinstalling/updating the extension (sometimes via the portal "Retry" or removing and re-adding) typically resolves backup failures. Recreate/move/replication are heavy-handed and unrelated.$az104r$, $az104r$[{"url":"https://learn.microsoft.com/en-us/azure/backup/backup-azure-vms-introduction","label":"Microsoft Learn — Azure VM backup overview"},{"url":"https://learn.microsoft.com/en-us/azure/virtual-machines/extensions/overview","label":"Microsoft Learn — Virtual machine extensions and features"}]$az104r$::jsonb, $az104r$PUBLISHED$az104r$::"QStatus", $az104r$manual:az104-seed$az104r$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.slug = $az104r$microsoft-az-104-p3$az104r$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $az104r$A VM Backup repeatedly fails with an extension error. Which step is typically the first remediation?$az104r$);
